import type { Drill } from "./types";

// Early-career (individual contributor) drills, keyed by module slug — 25 per
// module. Pitched at people with no direct reports: clear emails/updates,
// speaking up, asking good questions, managing up. Merged into course.ts.
export const EARLY_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-early-01","level":"early","title":"The buried standup update","scenario":"It's your turn in standup. You finished the search-filter feature yesterday, and it's already merged. You tend to narrate everything you touched before getting to what actually matters.","task":"Write a 1-2 sentence standup update that leads with the headline.","tips":["First words = the status: done, merged, or blocked?","Skip the play-by-play of every commit.","Mention what's next only if it's short."],"focus":["concision","structure"],"placeholder":"Search filter is merged and live —"},
    {"id":"lead-early-02","level":"early","title":"The blocked-but-vague Slack","scenario":"You're stuck because you don't have access to the staging database, and only your manager can grant it. You start typing a long message explaining everything you tried first.","task":"Write a Slack message that puts the ask in the first sentence.","tips":["Lead with what you need and from whom.","Backstory of what you tried is support — put it after.","Make the action you want obvious."],"focus":["clarity","impact"],"placeholder":"I'm blocked and need staging DB access —"},
    {"id":"lead-early-03","level":"early","title":"The status email that hides the news","scenario":"Your manager asked for a quick update on the API integration. The real news: it's done a day early. You're tempted to open with how the week went before sharing that.","task":"Write a 2-3 sentence email that leads with the good news.","tips":["Put the result in sentence one — early, done, on track.","Don't make your manager read to the bottom for the punchline.","Detail becomes optional support below."],"focus":["structure","concision"]},
    {"id":"lead-early-04","level":"early","title":"The PR description with no point","scenario":"You open a pull request titled 'updates' with a description that lists files you changed. A reviewer can't tell what the PR does or why it matters without reading the diff.","task":"Write a PR description where the first line states what the PR does and why.","tips":["First line = the change and its purpose, in plain words.","Reviewers triage by the opening — make it count.","List of files is support, not the headline."],"focus":["clarity","structure"],"placeholder":"Fixes the duplicate-email bug on signup by..."},
    {"id":"lead-early-05","level":"early","title":"The question buried in context","scenario":"You want to ask a senior engineer whether you should use the cache layer or hit the DB directly. You've drafted three paragraphs of setup before the actual question appears.","task":"Rewrite the message so the question comes first.","tips":["Ask the question in sentence one.","Give just enough context for them to answer — no more.","A clear question gets a faster answer."],"focus":["concision","clarity"],"placeholder":"Quick question: cache layer or direct DB read for the new endpoint?"},
    {"id":"lead-early-06","level":"early","title":"The 'circling back' nudge","scenario":"You asked a peer to review your design doc two days ago and heard nothing. You want to follow up, but your draft starts with apologies and 'just circling back when you have a sec.'","task":"Write a follow-up that leads with the specific ask and a soft deadline.","tips":["Name exactly what you need: a review by when.","Cut the apologetic warm-up.","One clear ask beats a vague nudge."],"focus":["clarity","impact"]},
    {"id":"lead-early-07","level":"early","title":"The estimate they actually want","scenario":"Your manager asked when the export feature will be ready. You know the answer is 'Thursday,' but you start by explaining all the edge cases you're still handling.","task":"Write a reply that gives the date first, then the caveat.","tips":["Lead with the date — that's the question they asked.","Caveats and risks come after the headline.","Don't make them dig for the number."],"focus":["precision","structure"],"placeholder":"Thursday, assuming the CSV edge case holds —"},
    {"id":"lead-early-08","level":"early","title":"The bug report with no verdict","scenario":"You're messaging your team that you found a bug in checkout. It's serious — it double-charges some users. Your draft walks through how you discovered it before naming the impact.","task":"Write a message that leads with the severity and impact.","tips":["First sentence: what's broken and how bad.","Repro steps are support — put them below.","Urgency should be obvious from the opening."],"focus":["impact","clarity"],"placeholder":"Checkout is double-charging some users — high priority."},
    {"id":"lead-early-09","level":"early","title":"The weekly summary that meanders","scenario":"You send your manager a Friday recap. This week you shipped two fixes and one small feature, but spent half the email recapping meetings you attended.","task":"Write the opening line of a recap that leads with what you shipped.","tips":["Lead with outcomes, not activity.","Meetings attended are not the headline.","One crisp summary sentence, then bullets."],"focus":["concision","structure"],"placeholder":"This week: shipped the password-reset fix and the CSV export —"},
    {"id":"lead-early-10","level":"early","title":"The slip you're afraid to say","scenario":"The feature you promised for Tuesday won't be ready until Friday. You're nervous, so your message to your manager opens with everything that went wrong before admitting the new date.","task":"Write a 2-3 sentence message that states the new date up front.","tips":["Lead with the new date — that's what they need.","Reasons come after, briefly.","Owning it clearly builds more trust than burying it."],"focus":["clarity","impact"],"placeholder":"The export feature will slip to Friday."},
    {"id":"lead-early-11","level":"early","title":"The recommendation hidden in analysis","scenario":"A peer asked which of two libraries to use for date parsing. You compared them thoroughly and have a clear pick, but your reply lists pros and cons for paragraphs before recommending one.","task":"Rewrite so your recommendation comes first, with reasons after.","tips":["State your pick in sentence one.","Pros and cons become the supporting detail.","Make the decision easy to act on."],"focus":["structure","clarity"],"placeholder":"Go with date-fns —"},
    {"id":"lead-early-12","level":"early","title":"The demo intro that wanders","scenario":"You're about to demo your new feature to the team at the end of sprint. You want to open by walking through the whole history of the ticket before showing what it does.","task":"Write the first two sentences of your demo that lead with what the feature does for users.","tips":["Open with the user-facing result.","Save the backstory of the ticket for later or skip it.","Let them see the point before the process."],"focus":["audience","impact"]},
    {"id":"lead-early-13","level":"early","title":"The help request that hides the ask","scenario":"You need a teammate to pair with you for 30 minutes on a tricky merge conflict this afternoon. Your draft explains the whole branching situation before getting to the ask.","task":"Write a Slack message that leads with the specific request.","tips":["Lead with the ask: 30 minutes, this afternoon, pairing.","Context on the conflict is support.","Make it easy to say yes or propose a time."],"focus":["clarity","concision"],"placeholder":"Could you pair with me for 30 min this afternoon on a merge conflict?"},
    {"id":"lead-early-14","level":"early","title":"The on-call handoff","scenario":"You're handing off on-call to a peer. There's one active issue they must watch — a flaky deploy — but your handoff note starts with a calm recap of the quiet week.","task":"Write a handoff note that leads with the one thing they must watch.","tips":["First line: the active risk and what to do.","Everything that's fine can come after.","If they read only one line, it should be the live issue."],"focus":["precision","structure"],"placeholder":"Watch the staging deploy — it's been flaky and may page you."},
    {"id":"lead-early-15","level":"early","title":"The disagreement that takes too long","scenario":"In a thread, a teammate proposed an approach you think is risky. You want to push back, but your draft spends four sentences agreeing and softening before stating your concern.","task":"Write a reply that states your concern first, then the reasoning.","tips":["Lead with the concern, respectfully and plainly.","Reasoning and alternatives follow.","Don't bury the point under cushioning."],"focus":["clarity","impact"]},
    {"id":"lead-early-16","level":"early","title":"The test results nobody can parse","scenario":"You ran the new test suite and three tests failed — all pointing to the same root cause. Your message to the channel pastes raw logs before saying what it means.","task":"Write a message that leads with the conclusion, then the evidence.","tips":["First sentence: what the failures mean and the likely cause.","Logs are evidence — put them below.","Tell people the takeaway before the detail."],"focus":["clarity","structure"],"placeholder":"Three tests fail because of one null-check —"},
    {"id":"lead-early-17","level":"early","title":"The 'should I keep going?' check-in","scenario":"You're halfway through a refactor that's growing bigger than expected. You want your manager's call on whether to finish it or stop. Your draft describes the refactor in detail before asking.","task":"Write a message that puts the decision you need first.","tips":["Lead with the decision: keep going or pause?","Give the tradeoff in a sentence, not a paragraph.","Make the choice clear and bounded."],"focus":["clarity","concision"],"placeholder":"I need a quick call: finish the refactor (2 more days) or ship as-is?"},
    {"id":"lead-early-18","level":"early","title":"The release-note headline","scenario":"You're writing the note that goes out when your fix ships. The most important thing for users is that login no longer fails on slow connections, but your draft opens with internal implementation details.","task":"Write a release-note opening line that leads with the user benefit.","tips":["Lead with what changed for the user.","Implementation detail is for the curious, lower down.","Match the headline to what the reader cares about."],"focus":["audience","impact"],"placeholder":"Login now works reliably on slow connections."},
    {"id":"lead-early-19","level":"early","title":"The reply that answers everything but the question","scenario":"Your manager asked one yes/no question in Slack: can the feature flag be turned on for everyone? You know it can, but your reply gives three paragraphs of context before saying yes.","task":"Write a reply that answers yes/no first, then adds the caveat.","tips":["Answer the actual question in word one or two.","Caveats follow the answer.","Don't make them re-read to find your verdict."],"focus":["concision","clarity"],"placeholder":"Yes — safe to enable for everyone, with one caveat:"},
    {"id":"lead-early-20","level":"early","title":"The estimate-too-low warning","scenario":"A task your team scoped as one day is clearly going to take three. You need to flag this to your manager now, but your draft eases in with how complex the codebase is.","task":"Write a heads-up that leads with the revised estimate.","tips":["Lead with the new number: three days, not one.","Why it grew is support, kept short.","Flag early and plainly — surprises are worse."],"focus":["precision","impact"],"placeholder":"Heads-up: this is now a 3-day task, not 1."},
    {"id":"lead-early-21","level":"early","title":"The retro point that loses the room","scenario":"In the sprint retro you want to raise that the unclear ticket descriptions cost the team time this sprint. Your draft starts with a long story about one specific ticket before naming the pattern.","task":"Write a retro comment that names the issue first, then the example.","tips":["State the pattern up front: unclear tickets cost us time.","Use the specific ticket as supporting evidence.","Lead with the takeaway you want acted on."],"focus":["structure","clarity"]},
    {"id":"lead-early-22","level":"early","title":"The 'I broke prod' message","scenario":"A deploy you pushed took down the search page for a few minutes. It's recovered now. You need to tell the team, but your instinct is to explain the whole sequence before saying it's resolved.","task":"Write a message that leads with current status: resolved.","tips":["First line: what happened and that it's fixed now.","The blow-by-blow is support below.","People need the status before the story."],"focus":["clarity","impact"],"placeholder":"Search went down for ~3 min after my deploy — it's recovered now."},
    {"id":"lead-early-23","level":"early","title":"The vague meeting request","scenario":"You want 15 minutes with your manager to talk through your career goals. Your draft message dances around the topic with 'when you get a chance, maybe we could chat about some stuff.'","task":"Write a request that states the purpose and the time you need up front.","tips":["Lead with what the meeting is for and how long.","Vagueness makes it easy to deprioritize.","Specific asks get on the calendar."],"focus":["clarity","precision"],"placeholder":"Could I grab 15 min this week to talk through my growth goals?"},
    {"id":"lead-early-24","level":"early","title":"The 'two options' decision email","scenario":"You've narrowed a UI approach down to two options and need a peer to weigh in by tomorrow. Your draft explains the design constraints for several sentences before presenting the choice.","task":"Write an email that leads with the decision and deadline, then lays out the two options.","tips":["Open with the decision needed and by when.","Then present Option A vs B cleanly.","Make it skimmable — one read, clear choice."],"focus":["structure","clarity"],"placeholder":"Need your pick between two layouts by tomorrow EOD —"},
    {"id":"lead-early-25","level":"early","title":"The thank-you that hides the favor","scenario":"A senior teammate unblocked you yesterday, and now you need one more small thing — a quick review of your follow-up PR. Your draft is all gratitude with the new ask buried in the last line.","task":"Write a message that makes the new ask clear early, while still being gracious.","tips":["Lead with the ask, then the thanks — or pair them in the first line.","Don't make them read past the gratitude to find the favor.","Keep it warm but unmissable."],"focus":["clarity","audience"]}
  ],
  "start-with-the-audience": [
    {"id":"audience-early-01","level":"early","title":"Status update for your manager","scenario":"Your manager asked for a quick update on the data-import task you've been on all week. You want to write back something like: \"I refactored the parser to handle nested CSV edge cases and added retry logic to the ingestion job.\" But your manager just wants to know if it'll ship on time.","task":"Rewrite your update in 2-3 sentences so it leads with what your manager actually cares about.","tips":["Lead with the status and timeline, not the implementation details.","Translate the technical work into progress your manager can act on.","Mention blockers only if they affect the date."],"focus":["audience","clarity"],"placeholder":"On track to ship Thursday. This week I…"},
    {"id":"audience-early-02","level":"early","title":"Explain the bug to support","scenario":"A support teammate pings you because customers are seeing errors. The real cause: \"A null foreign key in the orders table is throwing a 500 in the checkout service.\" The support agent has no engineering background and needs to tell customers something.","task":"Write a 2-3 sentence explanation the support agent can understand and partly relay to customers.","tips":["Skip the database internals; name the symptom and the fix.","Give support a customer-safe sentence they can reuse.","Say whether customers need to do anything."],"focus":["audience","clarity"]},
    {"id":"audience-early-03","level":"early","title":"Hand off to the design team","scenario":"You finished the API that the design team will build a screen against. Your instinct is to send them the endpoint spec and a list of response fields. But the designers care about what data they can show users and when it's available, not your route names.","task":"Write a short handoff note (3-4 sentences) framed around what design can now do.","tips":["Lead with the user-facing capability the API unlocks.","Translate field names into 'what the screen can show'.","Flag anything that isn't available yet."],"focus":["audience","structure"]},
    {"id":"audience-early-04","level":"early","title":"Ask a question that gives context","scenario":"You're stuck and want to ask a senior engineer for help. You start to type: \"Why doesn't this work?\" with a screenshot. They have no idea what you tried, what you expected, or what you already ruled out.","task":"Rewrite your help request so the reader can answer without a back-and-forth.","tips":["Name what you expected, what happened, and what you already tried.","Give just enough context to place the problem.","Make it easy to answer in one reply."],"focus":["audience","precision"],"placeholder":"I'm trying to X. I expected Y but got Z. I already checked…"},
    {"id":"audience-early-05","level":"early","title":"Reply to a non-technical stakeholder","scenario":"A marketing teammate emails asking when the new signup flow will be ready. You could answer: \"Once the A/B test reaches significance and we merge the feature flag rollout.\" They don't know what a feature flag is and just want a date.","task":"Write a 2-3 sentence reply that answers their real question in their language.","tips":["Give a date or a range first.","Translate the technical gating step into plain terms.","Offer to flag them when it's live."],"focus":["audience","clarity"]},
    {"id":"audience-early-06","level":"early","title":"Name what the reader already knows","scenario":"You're writing a message to a teammate who joined the project yesterday, explaining a fix. You almost reference \"the usual nightly job\" and \"the thing we discussed in standup\" — context they don't have yet.","task":"Rewrite a short explanation (3-4 sentences) that assumes the reader knows nothing about your project's history.","tips":["Beat the curse of knowledge: spell out the shorthand.","Build the missing bridge before the detail.","Define one term the newcomer wouldn't know."],"focus":["audience","clarity"]},
    {"id":"audience-early-07","level":"early","title":"Help-desk reply to a frustrated user","scenario":"A user wrote in angry that the export feature 'is broken.' You discover they're using an unsupported file format. You want to reply, but your first draft starts with \"The CSV parser only accepts UTF-8 encoded files.\"","task":"Write a 2-4 sentence reply that helps the user fix it without jargon.","tips":["Lead with how they can succeed, not what they did wrong.","Translate the technical limit into a simple instruction.","Keep the tone helpful, not defensive."],"focus":["audience","impact"]},
    {"id":"audience-early-08","level":"early","title":"Two readers, one message","scenario":"You're sending an update that both your manager and a partner team will read. Your manager cares about your timeline; the partner team cares about whether your change breaks their integration. You're tempted to cram both concerns into one tangled paragraph.","task":"Write the update choosing one primary reader, with the other able to read over their shoulder.","tips":["Pick the primary decision-maker and write for them.","Don't flatten both concerns into mush.","Use a clear line or section for the secondary reader."],"focus":["audience","structure"]},
    {"id":"audience-early-09","level":"early","title":"Translate metrics for a teammate","scenario":"You ran an analysis and want to share it with a product teammate. Your draft says: \"p95 latency dropped from 800ms to 300ms after the index change.\" They don't know what p95 means or why it matters to them.","task":"Rewrite the finding in 2-3 sentences so the product teammate sees why it matters.","tips":["Translate the metric into user-felt experience.","Say what changed and why the reader should care.","Keep one number if it helps, but explain it."],"focus":["audience","clarity"]},
    {"id":"audience-early-10","level":"early","title":"Lead with the answer","scenario":"A teammate asked in chat: \"Can we use the new library?\" You start typing a long walkthrough of the licensing terms, the dependency tree, and the maintenance history before getting to your verdict.","task":"Rewrite your reply so it leads with the answer, then the reasons.","tips":["Put your yes/no/it-depends in the first line.","Give the reader the bottom line before the detail.","Let them stop reading once they have what they need."],"focus":["audience","structure"]},
    {"id":"audience-early-11","level":"early","title":"Onboarding note for the next hire","scenario":"You're documenting a setup process for whoever joins next. Your first draft is full of \"obviously\" and \"just run the usual script\" — phrases that make sense to you after six months but mean nothing to a new person.","task":"Rewrite a few setup steps so a brand-new teammate could follow them with no prior context.","tips":["Beat the curse of knowledge: remove every 'obviously'.","Spell out the 'usual' steps explicitly.","Name where to find anything you reference."],"focus":["audience","precision"]},
    {"id":"audience-early-12","level":"early","title":"Email another team for a favor","scenario":"You need the platform team to bump a rate limit for your service. Your draft dives straight into your service's traffic patterns and config. They get dozens of these requests and care about what you need and why it's safe.","task":"Write a 3-4 sentence request framed around what the platform team needs to decide.","tips":["Lead with the specific ask: what, where, how much.","Give them the reason and the safety angle.","Make it easy to say yes quickly."],"focus":["audience","concision"]},
    {"id":"audience-early-13","level":"early","title":"Demo notes for the sales team","scenario":"You built a feature and the sales team wants to show it to customers. You wrote notes describing the architecture and the toggle that enables it. Sales needs to know what to say and what the customer will see.","task":"Rewrite the demo notes (3-5 sentences) for a salesperson who can't see the code.","tips":["Describe the customer-visible benefit, not the internals.","Give them words a customer would care about.","Note any limitation they should avoid promising."],"focus":["audience","impact"]},
    {"id":"audience-early-14","level":"early","title":"Flag a risk to your manager","scenario":"You noticed the deadline is at risk because a dependency is late. You could bury this in technical detail about the blocked module, but your manager needs to know the impact and the options now.","task":"Write a 2-4 sentence heads-up that leads with the impact and gives options.","tips":["Lead with what's at risk and by how much.","Translate the cause into one plain sentence.","Offer a choice, not just a problem."],"focus":["audience","impact"]},
    {"id":"audience-early-15","level":"early","title":"Comment for the next reader of your code","scenario":"You wrote a tricky workaround and added the comment: \"Hack for the thing.\" The next engineer who reads it — maybe you in six months — won't know what 'the thing' was or why the workaround exists.","task":"Rewrite the comment so a future reader understands the why without asking you.","tips":["Name the problem the workaround solves.","Assume the reader has none of today's context.","Say what would let this be removed later."],"focus":["audience","precision"]},
    {"id":"audience-early-16","level":"early","title":"Reply to QA's bug report","scenario":"A QA tester filed a bug. You investigated and it's actually expected behavior under a config they didn't know about. Your draft reply is \"Working as intended, closing.\" — which will frustrate them and teach them nothing.","task":"Write a 2-4 sentence reply that explains it from QA's point of view.","tips":["Acknowledge what they saw before explaining.","Translate the config detail into why it behaves that way.","Tell them how to test it correctly next time."],"focus":["audience","clarity"]},
    {"id":"audience-early-17","level":"early","title":"Summarize a doc for a busy reader","scenario":"You wrote a detailed technical design doc and need a teammate to weigh in. They're slammed and won't read five pages. You need them to grasp the decision and the one thing you need from them.","task":"Write a 2-3 sentence summary that gives a time-pressed reader the gist and the ask.","tips":["Calibrate altitude: higher-level and shorter for a busy reader.","Lead with the decision, not the background.","End with the one specific thing you need from them."],"focus":["audience","concision"]},
    {"id":"audience-early-18","level":"early","title":"Standup update people can follow","scenario":"In standup you tend to say things like \"I was debugging the serializer mismatch in the v2 endpoint.\" Half the room works on different areas and has no idea what that means or whether it affects them.","task":"Rewrite your standup update so anyone on the team understands it in one line.","tips":["Name the feature or outcome, not the internal component.","Say whether it affects or blocks anyone.","Keep it to a sentence or two."],"focus":["audience","concision"]},
    {"id":"audience-early-19","level":"early","title":"Explain your work to a relative","scenario":"A non-technical relative asks what you actually did at work this week. You catch yourself about to say \"I migrated our auth flow to OAuth and deprecated the legacy token endpoint.\" They have no frame for any of that.","task":"Explain what you did in 2-3 sentences using only words a non-technical person knows.","tips":["Translate the task into its real-world purpose.","Use an everyday analogy if it helps.","Drop every acronym."],"focus":["audience","clarity"]},
    {"id":"audience-early-20","level":"early","title":"Release notes for end users","scenario":"You shipped a fix and need to write the user-facing release note. Your draft: \"Resolved a race condition causing intermittent 404s on the profile route.\" Users don't know what any of that means — they just experienced 'my profile sometimes didn't load.'","task":"Rewrite the release note in plain language users will recognize.","tips":["Describe the symptom the user noticed, then the fix.","Drop the internal terms entirely.","Keep it short and reassuring."],"focus":["audience","clarity"]},
    {"id":"audience-early-21","level":"early","title":"Pitch a small improvement to your team","scenario":"You want to suggest adding a linter to the project. You're excited about code cleanliness, but your teammates care about whether it slows them down or catches real problems.","task":"Write a 3-4 sentence pitch framed around what your teammates get out of it.","tips":["Lead with the benefit to the reader's daily work.","Address the cost or friction they'll worry about.","Cut anything that's only exciting to you."],"focus":["audience","impact"]},
    {"id":"audience-early-22","level":"early","title":"Cross-team Slack question","scenario":"You drop into another team's channel and ask: \"Is the thing down?\" They don't know who you are, what 'the thing' is, or what you're seeing. You'll get silence or ten clarifying questions.","task":"Rewrite your message so a stranger on another team can help immediately.","tips":["Introduce who you are and what you're working on briefly.","Name the specific service and what you observed.","Say what answer would unblock you."],"focus":["audience","precision"]},
    {"id":"audience-early-23","level":"early","title":"Calibrate detail to the reader","scenario":"Two people asked about the same outage: your manager, who wants to know if it's resolved and who was affected, and a fellow engineer, who wants to know the root cause to avoid repeating it. You're tempted to send both the same long paragraph.","task":"Write two short versions of the same update — one for your manager, one for the engineer.","tips":["Same facts, different altitude for each reader.","Manager: impact and resolution. Engineer: cause and mechanism.","Keep each to 2-3 sentences."],"focus":["audience","structure"]},
    {"id":"audience-early-24","level":"early","title":"Rewrite a jargon-heavy sentence","scenario":"You wrote in a wiki page: \"The webhook handler idempotently dedupes events via the upstream correlation ID before enqueueing.\" A teammate from the support team will read this page and bounce right off it.","task":"Rewrite the sentence so a non-engineer reader can follow what happens.","tips":["Replace each jargon term with what it does in plain words.","Keep it accurate but readable.","Test it against someone who doesn't know the system."],"focus":["audience","clarity"]},
    {"id":"audience-early-25","level":"early","title":"Frame your ask around their goal","scenario":"You want a teammate to review your pull request quickly. Your draft just says \"Can you review my PR?\" with a link. They don't know how big it is, how urgent, or why it matters to anything they care about.","task":"Rewrite the review request so it connects to something the reviewer cares about.","tips":["Say what it unblocks and how long the review will take.","Connect it to a shared goal or deadline.","Make the size and urgency clear up front."],"focus":["audience","impact"]}
  ],
  "structure-that-carries": [
    {"id":"structure-early-01","level":"early","title":"Answer first in a status update","scenario":"Your team lead pings the group channel asking whether the checkout feature will be ready for Friday's release. You've done the work and the answer is yes, with one small caveat about the discount-code edge case.","task":"Write a 2-3 sentence reply that leads with the answer, then gives the caveat.","tips":["Put 'Yes' (or 'On track') in the very first sentence.","Add the caveat after the answer, not before it.","Don't make them scroll to find your conclusion."],"focus":["structure","clarity"]},
    {"id":"structure-early-02","level":"early","title":"Group the standup notes","scenario":"Your raw standup notes read: 'fixed the login redirect, replied to three QA comments, the staging deploy is stuck, still waiting on design specs, wrote tests for the API, the staging DB looks misconfigured.' It's a jumble of done, in-progress, and blocked items.","task":"Reorganize these into clear groups so a reader sees status at a glance.","tips":["Try buckets like Done, In progress, Blocked.","Put each note under exactly one bucket.","Lead each group with its label so it scans fast."],"focus":["structure","clarity"]},
    {"id":"structure-early-03","level":"early","title":"Frame the bug with SCQA","scenario":"Users on the mobile app could always upload a profile photo. After last week's release, uploads over 5MB silently fail with no error shown. You think we should add a size check and a clear error message.","task":"Write a short framing using Situation, Complication, Question, Answer.","tips":["Situation: what worked before and everyone agrees on.","Complication: exactly what changed and broke.","Question then Answer: name the question, then your one-line fix."],"focus":["structure","precision"]},
    {"id":"structure-early-04","level":"early","title":"Lead the recap email","scenario":"You just finished a two-week task migrating the old reporting script to the new pipeline. You want to email your team a recap, and you tend to start with all the background before getting to the result.","task":"Write the opening two sentences that state the outcome first, before any backstory.","tips":["Sentence one is the result: it's done and it works.","Save the how-it-went detail for after the headline.","Imagine a busy reader who only reads line one."],"focus":["structure","impact"]},
    {"id":"structure-early-05","level":"early","title":"Three buckets, not nine reasons","scenario":"A teammate asks why the nightly job has been flaky. You can list nine causes: a slow query, a retry bug, a memory leak, a flaky test, a timezone bug, an expired cert, a disk-space warning, a race condition, and a noisy log.","task":"Rewrite as one governing statement plus 2-3 grouped causes.","tips":["Find categories: code bugs, infrastructure, and config often work.","Open with a single sentence naming the real story.","Group the nine so they're memorable, don't list all of them flat."],"focus":["structure","concision"]},
    {"id":"structure-early-06","level":"early","title":"Top-down FAQ answer","scenario":"A new teammate keeps asking in chat how to run the test suite locally. You decide to write a short FAQ entry so the answer is reusable, but your draft buries the actual command three paragraphs down.","task":"Restructure the answer so the command comes first, with context after.","tips":["Give the direct answer or command in the first line.","Put prerequisites and caveats below the answer.","Readers skim FAQs; reward them immediately."],"focus":["structure","clarity"]},
    {"id":"structure-early-07","level":"early","title":"PREP your stand-up opinion","scenario":"In sprint planning a teammate proposes hand-rolling a date parser. You think the team should use the existing library instead, but on the spot you tend to ramble.","task":"Make your case in four moves: Point, Reason, Example, Point.","tips":["Point: state the claim in one sentence.","Reason then Example: why it's true, then a concrete instance.","Close by restating the point."],"focus":["structure","impact"]},
    {"id":"structure-early-08","level":"early","title":"Order the how-to steps","scenario":"You're documenting how to set up the project locally. Your notes have the steps out of order: 'run the seed script, clone the repo, install dependencies, copy the env file, start the server.' A newcomer would hit errors following them as written.","task":"Put the steps in the order a reader must actually do them.","tips":["Sequence by dependency: each step should be possible after the prior one.","Number the steps so order is unmistakable.","Read it as if you'd never seen the repo."],"focus":["structure","clarity"]},
    {"id":"structure-early-09","level":"early","title":"Headline the project recap","scenario":"Your end-of-sprint recap currently opens with: 'This sprint had some ups and downs and a few surprises along the way.' The real news is that you shipped the search feature a day early and one stretch goal slipped.","task":"Replace the vague opener with a one-line headline that names the real outcome.","tips":["Lead with the single most important fact.","Cut the throat-clearing 'ups and downs' opener.","One sentence should tell a skimmer how the sprint went."],"focus":["structure","impact"]},
    {"id":"structure-early-10","level":"early","title":"Group messy meeting notes","scenario":"You took notes in a planning meeting and ended up with a flat list of fourteen bullet points covering decisions, open questions, and action items all mixed together.","task":"Reorganize the flat list into three labeled sections.","tips":["Decisions, Open questions, and Action items are natural buckets.","Each bullet belongs under one heading.","Lead with the section labels so readers jump to what they need."],"focus":["structure","clarity"]},
    {"id":"structure-early-11","level":"early","title":"Frame the slow-page problem","scenario":"The settings page used to load instantly. Since a recent change it takes about four seconds, and users have started complaining in support tickets. You suspect an unindexed query and want to propose adding the index.","task":"Frame this with Situation, Complication, Question, Answer in 4-5 sentences.","tips":["Situation: the page used to be fast.","Complication: what changed and the impact users feel.","End with the question, then your one-line answer."],"focus":["structure","precision"]},
    {"id":"structure-early-12","level":"early","title":"Bottom line up front","scenario":"You're replying to a teammate who asked if the data export job finished overnight. Your draft walks through every step you checked before finally saying it failed at 3am.","task":"Rewrite so the bottom line comes first, then the supporting detail.","tips":["Open with the conclusion: it failed at 3am.","Put the investigation steps after the headline.","Don't bury the answer under your process."],"focus":["structure","concision"]},
    {"id":"structure-early-13","level":"early","title":"One governing idea","scenario":"Your draft retro post lists six separate complaints about the release process. Read together they're really one story: handoffs between QA and dev are unclear.","task":"Write a single governing sentence that names the theme, then slot the points beneath it.","tips":["Find the one idea that all six points support.","State it first; let the details hang under it.","A reader should grasp the point from the top line alone."],"focus":["structure","clarity"]},
    {"id":"structure-early-14","level":"early","title":"Order the update by what they need","scenario":"You're sending a weekly update to two teammates who depend on your work. One only cares whether the API contract changed; the other cares about timeline. Your draft mixes both topics randomly across five paragraphs.","task":"Restructure the update so each reader can find their part fast.","tips":["Group by topic, not by the order you happened to think of things.","Use short headers so readers scan to their section.","Lead with the item most readers care about most."],"focus":["structure","audience"]},
    {"id":"structure-early-15","level":"early","title":"PREP a tool recommendation","scenario":"A teammate asks in chat whether the team should adopt a linter on the project. You think yes, and want to answer with conviction instead of trailing off.","task":"Answer using Point, Reason, Example, Point.","tips":["Point: we should add the linter.","Reason and Example: why, plus a recent bug it would have caught.","Restate the point to land it."],"focus":["structure","impact"]},
    {"id":"structure-early-16","level":"early","title":"Triage the bug report","scenario":"Your bug report is a wall of text mixing what happened, what you expected, the steps to reproduce, and your environment details all in one paragraph.","task":"Restructure it into clear labeled parts a reader can scan.","tips":["Use sections: Expected, Actual, Steps to reproduce, Environment.","Lead with the one-line summary of the problem.","Each fact goes under exactly one label."],"focus":["structure","clarity"]},
    {"id":"structure-early-17","level":"early","title":"Summary line for a long thread","scenario":"A chat thread about a flaky deploy ran for forty messages. A teammate joins late and asks what's going on. You could paste the history, or you could lead with where things stand.","task":"Write a 2-3 sentence summary that states the current status first, then the key background.","tips":["First sentence: where things stand right now.","Then one or two lines of how we got here.","Spare the latecomer from reading all forty messages."],"focus":["structure","concision"]},
    {"id":"structure-early-18","level":"early","title":"Pyramid the release notes","scenario":"Your draft release notes list eleven changes in the order you committed them: a typo fix, a new export button, a dependency bump, a color tweak, a crash fix, and so on, all flat.","task":"Group the changes under a few themed headings with the most important first.","tips":["Try headings like New features, Fixes, and Maintenance.","Order groups so readers see what matters most up top.","Don't make users read eleven equal-weight bullets."],"focus":["structure","audience"]},
    {"id":"structure-early-19","level":"early","title":"Lead with the ask","scenario":"You need a teammate to review your pull request before end of day, but your message starts with three sentences explaining what the PR does before you finally make the request.","task":"Rewrite so the ask comes first, then the context.","tips":["Open with the request and the deadline.","Put the what-it-does explanation after the ask.","Make it easy to say yes by stating the need up front."],"focus":["structure","clarity"]},
    {"id":"structure-early-20","level":"early","title":"Frame the test-coverage gap","scenario":"The team has always relied on manual testing for the payments flow. A bug just slipped to production because no automated test covered refunds. You want to propose adding automated tests for that path.","task":"Write an SCQA framing in 4-5 sentences.","tips":["Situation: how testing works today, which everyone accepts.","Complication: the bug that got through and why.","Question then Answer: name it, then your recommendation."],"focus":["structure","precision"]},
    {"id":"structure-early-21","level":"early","title":"Reorder for the skimmer","scenario":"Your handoff doc for a teammate covering your tasks while you're out starts with low-priority nice-to-knows and ends with the one critical thing: the deploy must not run on Friday.","task":"Reorder the doc so the critical item is first.","tips":["Lead with the must-not-miss item.","Demote the nice-to-knows to the bottom.","Assume the reader stops halfway through."],"focus":["structure","audience"]},
    {"id":"structure-early-22","level":"early","title":"Group the feedback you got","scenario":"You collected eight pieces of code-review feedback on your PR. Some are about naming, some about error handling, and some about tests. Right now they're a flat to-do list.","task":"Group the eight items into themes and address them theme by theme.","tips":["Cluster by topic: naming, error handling, tests.","Name each theme before listing its items.","Grouping makes the work feel smaller and clearer."],"focus":["structure","concision"]},
    {"id":"structure-early-23","level":"early","title":"State the conclusion of your investigation","scenario":"You spent the morning tracing why a report showed wrong totals. You found the cause: a timezone mismatch double-counts one day. Your draft message replays the whole hunt before revealing it.","task":"Rewrite to lead with the root cause, then the supporting trail.","tips":["First line: the root cause in plain terms.","Then summarize how you confirmed it.","Readers want the answer before the journey."],"focus":["structure","clarity"]},
    {"id":"structure-early-24","level":"early","title":"Theme a long to-do email","scenario":"You're emailing yourself a brain-dump of everything left on your current task: ten items spanning code, documentation, and follow-up questions for a teammate, listed in the random order they occurred to you.","task":"Reorganize the ten items under a small number of themed headings.","tips":["Three to four headings beat one long flat list.","Put related items together under a clear label.","Order the headings by what you'll tackle first."],"focus":["structure","concision"]},
    {"id":"structure-early-25","level":"early","title":"PREP an estimate pushback","scenario":"A teammate suggests the API change is a one-day task. You've worked in that code and think it's closer to three days. You want to push back clearly without sounding defensive.","task":"Make your case with Point, Reason, Example, Point.","tips":["Point: this is closer to three days.","Reason and Example: the hidden complexity, plus a similar past task.","Restate the estimate to close."],"focus":["structure","precision"]}
  ],
  "cut-to-the-bone": [
    {"id":"concise-early-01","level":"early","title":"Trim the standup update","scenario":"Your async standup update reads: \"So I basically spent most of yesterday sort of digging into the login bug, and I think I might have maybe found something that could possibly be related to the session timeout, but I'm not totally sure yet.\" Your team skims these fast.","task":"Rewrite it in one or two plain sentences with no hedging.","tips":["Cut 'basically', 'sort of', 'might maybe', 'possibly'.","State what you found and what's still open.","Name the one real uncertainty instead of fogging it all."],"focus":["concision","clarity"],"placeholder":"Yesterday I traced the login bug to..."},
    {"id":"concise-early-02","level":"early","title":"Cut the email runway","scenario":"You're emailing a teammate to ask for a file. You wrote: \"Hi! I hope you're doing well and had a great weekend. I just wanted to quickly reach out because I was wondering if you might possibly have a moment to send over the Q2 spreadsheet whenever you get a chance.\"","task":"Rewrite it as a two-line message that still feels friendly.","tips":["Delete the runway and start at the ask.","One greeting line, one ask line is enough.","Warm does not require warm-up."],"focus":["concision","audience"]},
    {"id":"concise-early-03","level":"early","title":"Nominalizations to verbs","scenario":"Your release note says: \"The implementation of the caching layer led to a reduction in the load time of the dashboard for the majority of users.\"","task":"Rewrite it using strong verbs instead of -tion noun-phrases.","tips":["Hunt words ending in -tion and -ment.","'Implementation of' becomes 'we built'; 'reduction in' becomes 'cut'.","Aim to roughly halve the word count."],"focus":["concision","precision"]},
    {"id":"concise-early-04","level":"early","title":"Shrink the Slack thread","scenario":"A teammate asks in Slack whether the deploy is done. You start typing a five-sentence reply explaining the whole history of the deploy, the staging hiccup, and your lunch break.","task":"Answer the actual question in one line, then offer detail only if wanted.","tips":["Lead with yes/no/almost.","They asked a status, not a story.","Park the backstory behind 'happy to share more if useful'."],"focus":["concision","audience"]},
    {"id":"concise-early-05","level":"early","title":"Halve the recap","scenario":"After a sync, you wrote: \"I just wanted to take a moment to recap some of the various things we discussed and the different action items that came out of our conversation earlier today so that we're all hopefully on the same page going forward.\"","task":"Replace that whole opener with a single short line that leads into the list.","tips":["Nobody needs an intro to a recap — just recap.","'Here's what we agreed:' is a complete runway.","Cut 'various', 'different', 'hopefully'."],"focus":["concision","structure"]},
    {"id":"concise-early-06","level":"early","title":"De-hedge the estimate","scenario":"Your lead asks when a task will be done. You reply: \"Um, it's kind of hard to say exactly, but I'm thinking it could maybe be sometime around the end of the week, give or take, assuming nothing else comes up.\"","task":"Give a clear estimate and name the one real risk if there is one.","tips":["Commit to a day, then qualify once.","'Friday, unless the API access is delayed' beats five soft words.","A specific caveat is honest; vague fog is not."],"focus":["precision","concision"]},
    {"id":"concise-early-07","level":"early","title":"Tighten the question","scenario":"You want to ask a senior engineer one thing in code review. You drafted: \"Sorry to bother you, I might be totally off base here and this is probably a dumb question, but I was just kind of wondering if maybe there's a reason we're not caching this result?\"","task":"Rewrite it as one direct, respectful question.","tips":["Drop the self-deprecation; it isn't politeness.","Ask the real question in one sentence.","Curiosity reads as confident, not rude."],"focus":["concision","impact"]},
    {"id":"concise-early-08","level":"early","title":"Cut filler from the PR description","scenario":"Your pull request description reads: \"This PR basically just does a few small things — it kind of cleans up some of the stuff in the utils file and also sort of fixes that thing where the date was occasionally showing up wrong in certain cases sometimes.\"","task":"Rewrite it as a crisp two-bullet summary of what changed.","tips":["Reviewers want what changed and why.","Cut 'basically', 'just', 'kind of', 'stuff', 'sometimes'.","Name the file and the actual bug."],"focus":["clarity","concision"]},
    {"id":"concise-early-09","level":"early","title":"One ask, not three paragraphs","scenario":"You need design files unblocked. Your message wanders through context, history, and feelings for three paragraphs before the request appears at the bottom.","task":"Lead with the ask in the first line, then give only the context that earns its place.","tips":["Put the request at the top, not the bottom.","Keep only context that changes their answer.","If they can act from line one, you've won."],"focus":["structure","concision"]},
    {"id":"concise-early-10","level":"early","title":"Kill the throat-clearing","scenario":"Your update opens with: \"It's worth noting that, as you may already be aware, the testing phase has been something that we've been working through over the past little while.\"","task":"Delete the meta-commentary and start at the actual point.","tips":["'It's worth noting' and 'as you may be aware' are pure runway.","Start with the fact itself.","If they already know it, you can cut it entirely."],"focus":["concision","clarity"]},
    {"id":"concise-early-11","level":"early","title":"Compress the bug report","scenario":"You're filing a ticket: \"So what happens is that when you click on the button, sometimes, not always, the page seems to kind of freeze for a bit and then eventually it comes back but the data looks like it might be wrong.\"","task":"Rewrite it as a tight steps-to-reproduce plus the actual problem.","tips":["State the trigger, the frequency, the result.","Replace 'sometimes', 'kind of', 'a bit' with specifics.","A clean repro saves the reader a reply."],"focus":["precision","concision"]},
    {"id":"concise-early-12","level":"early","title":"Drop the apology padding","scenario":"You're slightly late sending notes and wrote: \"I'm so so sorry for the delay, I really didn't mean to hold things up, things have just been super hectic on my end, apologies again for the wait on this.\"","task":"Rewrite it with one brief acknowledgement and then the notes.","tips":["One apology is plenty; three is noise.","Acknowledge, then deliver.","The notes matter more than the sorry."],"focus":["concision","audience"]},
    {"id":"concise-early-13","level":"early","title":"Tighten the handoff","scenario":"You're handing a half-done task to a teammate before vacation. Your note rambles across what you did, what you meant to do, and a tangent about a meeting, burying what they actually need to pick up.","task":"Rewrite it as: what's done, what's left, where to start.","tips":["Three short sections beat one long paragraph.","Cut the tangents that don't help them continue.","Make the 'start here' line unmissable."],"focus":["structure","concision"]},
    {"id":"concise-early-14","level":"early","title":"Halve the meeting recap email","scenario":"Recap a 30-minute meeting in which the team agreed to three things. Your draft is six dense sentences restating the discussion.","task":"Reduce it to a one-line summary plus three short action bullets with owners.","tips":["Decisions and owners are the payload.","The discussion itself rarely needs restating.","If a bullet has no owner, it isn't an action."],"focus":["structure","clarity"]},
    {"id":"concise-early-15","level":"early","title":"Cut the qualifiers","scenario":"You're recommending a library and wrote: \"I think this is probably a fairly reasonable option that might work pretty well for most of our likely use cases, more or less.\"","task":"State your recommendation plainly, then attach one concrete reason.","tips":["Stack of qualifiers reads as 'I don't know'.","Recommend, then give the strongest single reason.","If you genuinely doubt it, say what specifically worries you."],"focus":["impact","concision"]},
    {"id":"concise-early-16","level":"early","title":"Trim the intro to a demo","scenario":"Before showing your screen in a team demo you say: \"Okay so, um, before I get into it, I just want to give a little bit of background and kind of set the stage for what you're about to see here today.\"","task":"Replace that warm-up with one sentence that lands the demo's point.","tips":["Skip 'before I get into it' — get into it.","Tell them what they're about to see in one line.","Setup should orient, not stall."],"focus":["concision","audience"]},
    {"id":"concise-early-17","level":"early","title":"Shrink the redundancy","scenario":"Your doc says: \"In my personal opinion, I think that we should collaborate together as a team in order to combine and merge the two separate lists into one single unified list.\"","task":"Rewrite it with every redundant pair removed.","tips":["'Personal opinion', 'collaborate together', 'combine and merge' all double up.","'In order to' is almost always just 'to'.","Say it once."],"focus":["concision","precision"]},
    {"id":"concise-early-18","level":"early","title":"Get to the blocker fast","scenario":"You're blocked and posting in the team channel, but your message spends four sentences on what you tried before it ever says you're stuck or what you need.","task":"Rewrite it to lead with the blocker and the specific help you need.","tips":["Lead with 'I'm blocked on X, need Y.'","Move 'what I tried' below the ask.","People can only help once they see the ask."],"focus":["structure","concision"]},
    {"id":"concise-early-19","level":"early","title":"Cut the 'just' and 'really'","scenario":"Read your own draft: \"I just really wanted to just quickly check in and just see if you really had any thoughts on the thing I really sent over.\"","task":"Rewrite it deleting every 'just' and 'really', keeping the meaning.","tips":["These two words almost always add nothing.","Read it aloud without them — it's stronger.","Name 'the thing' specifically while you're at it."],"focus":["concision","clarity"]},
    {"id":"concise-early-20","level":"early","title":"Tighten the status line","scenario":"A project tracker asks for a one-line status. You wrote: \"Things are sort of moving along okay I think, making some progress here and there, should hopefully be wrapping up soonish.\"","task":"Rewrite it as one concrete status line with a real signal.","tips":["'On track for Thursday' beats 'moving along okay'.","Pick green/yellow/red, then one fact.","Soonish is not a status."],"focus":["precision","concision"]},
    {"id":"concise-early-21","level":"early","title":"Compress the long Slack ask","scenario":"You want a teammate to review your doc by tomorrow. Your message is a wall of text covering why the doc exists, how long it took, and a soft hope that maybe they could look if they have time.","task":"Rewrite it as a clear ask with the doc, the action, and the deadline.","tips":["Link, action, deadline — that's the message.","Cut the origin story of the doc.","A clear deadline is a courtesy, not a demand."],"focus":["concision","audience"]},
    {"id":"concise-early-22","level":"early","title":"One sentence, not five","scenario":"Someone asks what your feature does. You launch into five sentences about the architecture, the edge cases, and the history before answering.","task":"Answer in one sentence a non-expert teammate would understand.","tips":["Start with what it does for the user.","Hold the architecture unless they ask.","If they want depth, they'll follow up."],"focus":["clarity","concision"]},
    {"id":"concise-early-23","level":"early","title":"Strip the email sign-off bloat","scenario":"Your email ends: \"Anyway, thanks so much again for taking the time to read all of this, I really do appreciate it more than you know, and please don't hesitate at all to reach out if you have any questions whatsoever about anything at all.\"","task":"Rewrite the closing as one short, warm line.","tips":["'Thanks — happy to answer questions.' covers it.","Gratitude doesn't need three clauses.","A long sign-off undoes a tight email."],"focus":["concision","audience"]},
    {"id":"concise-early-24","level":"early","title":"Cut the caveats before the point","scenario":"In a planning thread you wrote: \"I don't have full context and I'm new to this part of the codebase and I could be wrong, but it seems like the import script is running twice.\"","task":"Lead with the observation, then add at most one honest caveat.","tips":["Put the finding first; it's useful even if you're new.","One caveat, not three.","'I may be missing context, but the script runs twice' is enough."],"focus":["impact","concision"]},
    {"id":"concise-early-25","level":"early","title":"Halve the onboarding note","scenario":"You're writing a quick note for the next new hire about setting up the dev environment. Your draft repeats steps, adds vague reassurance, and pads each instruction with 'you'll basically want to go ahead and...'.","task":"Rewrite it as a tight numbered list of imperative steps.","tips":["Use bare imperatives: 'Clone the repo. Run setup.'","Cut 'you'll want to go ahead and'.","One line per step, no padding."],"focus":["structure","concision"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-early-01","level":"early","title":"Soon means a date","scenario":"Your manager asks when the export feature will be ready. You started typing \"It should be done soon, almost there.\" You actually have two small bugs left and a code review pending.","task":"Rewrite your reply to give a concrete date and what's left, instead of 'soon'.","tips":["Name an actual day, not 'soon' or 'almost'.","List the one or two things still standing between you and done.","If there's a risk, say what could push the date."],"focus":["precision","clarity"],"placeholder":"It should be done soon, almost there..."},
    {"id":"precision-early-02","level":"early","title":"Quantify your week","scenario":"In your weekly status, you wrote: \"Made good progress on the onboarding tickets, knocked out a bunch of them.\" Your lead skims twenty of these updates and can't tell what 'a bunch' means.","task":"Rewrite the update so the numbers show exactly what you did this week.","tips":["Replace 'a bunch' with a count.","Say how many are left, not just how many are done.","Lead with the number that matters most."],"focus":["precision","concision"]},
    {"id":"precision-early-03","level":"early","title":"A bug report a dev can act on","scenario":"You found a problem and messaged the developer: \"The page is broken, it doesn't work right when I try to save.\" They reply asking which page, what browser, and what 'broken' means.","task":"Write a bug report with the specifics a developer needs to reproduce it.","tips":["Say what you did, what you expected, and what happened.","Include the page, the steps, and any error text.","One clear failure, not a vague 'doesn't work'."],"focus":["precision","structure"],"placeholder":"The page is broken, it doesn't work right when I try to save."},
    {"id":"precision-early-04","level":"early","title":"Cut the data dump","scenario":"You pasted six metrics into Slack: signups 820 (+4%), email opens 31%, page load 1.9s, bounce 44%, tickets 27 (-12%), trial-to-paid 6%. Your teammate replies: \"Okay... so what's the takeaway?\"","task":"State the single most important insight from these numbers in one or two sentences.","tips":["Pick the one number that tells a story.","Say why it matters, don't just list it.","Drop the metrics that didn't move."],"focus":["concision","impact"]},
    {"id":"precision-early-05","level":"early","title":"Replace 'a lot faster'","scenario":"You optimized a query and want to tell your team. You drafted: \"I made the report load a lot faster, it's way better now.\" You have the before and after timings in front of you.","task":"Rewrite the sentence using the real numbers instead of 'a lot' and 'way better'.","tips":["Give the before and after, not just 'faster'.","A percentage or a time saved beats 'a lot'.","Keep it to one tight sentence."],"focus":["precision","concision"],"placeholder":"I made the report load a lot faster, it's way better now."},
    {"id":"precision-early-06","level":"early","title":"The honest 'almost done'","scenario":"At standup you keep saying a task is 'almost done.' You've said it three days running. Your lead pulls you aside, confused about why it isn't finished.","task":"Give a precise status: what percent is genuinely complete, what specifically remains, and a realistic finish date.","tips":["Break 'almost' into the concrete steps left.","Be honest about what's blocking you.","Commit to a date you can actually hit."],"focus":["precision","clarity"]},
    {"id":"precision-early-07","level":"early","title":"Estimate with a number","scenario":"A teammate asks how long a small task will take. You want to say \"not long\" but they need it for their own planning.","task":"Give a specific estimate with a range and your main assumption, instead of 'not long'.","tips":["Offer a range (e.g., a number of hours or days), not a vibe.","State the assumption your estimate depends on.","Say what would make it take longer."],"focus":["precision","clarity"]},
    {"id":"precision-early-08","level":"early","title":"Name the actual error","scenario":"Your build failed and you messaged the channel: \"Something's wrong with the build, it keeps failing.\" Three people now have to ask you what the error says.","task":"Rewrite the message including the specific error and which step failed.","tips":["Paste or quote the actual error line.","Say which step or command failed.","Pre-empt the obvious follow-up questions."],"focus":["precision","clarity"],"placeholder":"Something's wrong with the build, it keeps failing."},
    {"id":"precision-early-09","level":"early","title":"From 'users love it' to evidence","scenario":"In a feature recap you wrote: \"Users really love the new search.\" Your lead asks what you're basing that on.","task":"Rewrite the claim with a specific piece of evidence a skeptic would accept.","tips":["Attach a number, a quote, or a usage stat to the claim.","Include the timeframe or sample size.","Make it checkable, not just enthusiastic."],"focus":["precision","impact"]},
    {"id":"precision-early-10","level":"early","title":"Specific blocker, specific ask","scenario":"You're stuck and posted: \"I'm kind of blocked on the API thing, can someone help?\" Nobody bites because they can't tell what you need.","task":"Rewrite it naming exactly what's blocking you and the specific help you need.","tips":["Name the exact thing that's stuck.","Say what you've already tried.","Ask for one concrete thing from one person."],"focus":["precision","clarity"]},
    {"id":"precision-early-11","level":"early","title":"Turn a metric into a sentence","scenario":"You noticed mobile signups jumped last week. You want to flag it, but you only have the raw number: 340 of 500 signups came from phones.","task":"Write one sentence that states the insight and the number that backs it.","tips":["Lead with the insight, follow with the number.","Convert the raw count into a share if it's clearer.","Don't make the reader do the math."],"focus":["clarity","precision"]},
    {"id":"precision-early-12","level":"early","title":"What → So what → Now what","scenario":"You found that 40% of support tickets last month were about one confusing form field. You want to raise it with your lead, not just report the number.","task":"Write 2–3 sentences: the fact, why it matters, and what you'd do about it.","tips":["State the fact with its number first.","Then say why it matters to the team.","End with the action you're proposing."],"focus":["structure","impact"]},
    {"id":"precision-early-13","level":"early","title":"Precise PR description","scenario":"You opened a pull request and wrote only: \"Fixed some stuff with the login.\" The reviewer has no idea what changed or why.","task":"Rewrite the description so the reviewer knows exactly what changed and what problem it solves.","tips":["Name the specific bug or behavior you fixed.","Say what you changed, in concrete terms.","Mention how you tested it."],"focus":["precision","structure"],"placeholder":"Fixed some stuff with the login."},
    {"id":"precision-early-14","level":"early","title":"Drop the hedges","scenario":"You wrote: \"I think this maybe might be roughly around a 20% improvement, or so, give or take.\" You actually measured it: 19%.","task":"Rewrite it as a clean, specific claim without the pile of hedges.","tips":["If you measured it, state it plainly.","Remove 'maybe', 'roughly', 'or so' when you have a number.","One hedge max, and only if the data is genuinely uncertain."],"focus":["concision","precision"],"placeholder":"I think this maybe might be roughly around a 20% improvement, or so, give or take."},
    {"id":"precision-early-15","level":"early","title":"Concrete demo recap","scenario":"After demoing your work you emailed: \"The demo went well and people seemed happy with it.\" Your manager wants to know what was actually decided or flagged.","task":"Rewrite the recap with the specific outcomes, decisions, or follow-ups from the demo.","tips":["List what was decided, not how it 'felt'.","Name any follow-up items and who owns them.","Cut 'went well' unless you back it with a fact."],"focus":["precision","structure"]},
    {"id":"precision-early-16","level":"early","title":"Pin down 'a few'","scenario":"You told QA: \"I fixed a few of the issues you reported, the rest are kind of edge cases.\" QA needs to know which ones to re-test.","task":"Rewrite it specifying which issues you fixed and which remain, by reference.","tips":["Reference the specific ticket numbers or titles.","Separate 'fixed' from 'still open' clearly.","Replace 'a few' and 'kind of' with specifics."],"focus":["precision","clarity"]},
    {"id":"precision-early-17","level":"early","title":"One number that lands","scenario":"You ran a small experiment and want to share the result in the team channel. You have conversion before (4.1%) and after (5.3%). You're tempted to write a paragraph of context first.","task":"Write a one-line result that leads with the number and the change it represents.","tips":["Lead with the headline number, not the setup.","Show the before-and-after or the delta.","Save the long context for if someone asks."],"focus":["concision","impact"]},
    {"id":"precision-early-18","level":"early","title":"Specific time-off request","scenario":"You messaged your manager: \"Hey, I was hoping to maybe take some time off sometime next month if that's okay?\" They can't act on something this vague.","task":"Rewrite the request with exact dates and how your work is covered.","tips":["Give the precise start and end dates.","Say what's in flight and how it's handled.","Make it easy to just say yes."],"focus":["precision","clarity"],"placeholder":"Hey, I was hoping to maybe take some time off sometime next month if that's okay?"},
    {"id":"precision-early-19","level":"early","title":"Evidence for your recommendation","scenario":"You want to suggest switching a library. You wrote: \"I feel like the new library is just better for us.\" Your teammate asks why.","task":"Rewrite the recommendation with two concrete, checkable reasons.","tips":["Replace 'feel like' and 'just better' with specifics.","Give measurable reasons (size, speed, support).","Name the tradeoff you're aware of."],"focus":["precision","impact"]},
    {"id":"precision-early-20","level":"early","title":"Scope a vague request precisely","scenario":"A teammate asked you to \"clean up the dashboard a bit.\" Before you start, you want to confirm exactly what they mean so you don't guess wrong.","task":"Write a reply that restates the task as a specific, bounded scope to confirm.","tips":["Turn 'a bit' into a concrete list of changes.","State what you'll do and what you won't.","Ask one sharp confirming question."],"focus":["precision","clarity"]},
    {"id":"precision-early-21","level":"early","title":"Quantify the impact","scenario":"You automated a manual step and want to note it in your self-review. You wrote: \"Saved the team a bunch of time with a script.\" You know it ran 30 minutes daily.","task":"Rewrite it quantifying the time saved over a meaningful period.","tips":["Turn the per-run saving into a weekly or monthly total.","Replace 'a bunch' with the actual figure.","Tie the number to who benefits."],"focus":["precision","impact"],"placeholder":"Saved the team a bunch of time with a script."},
    {"id":"precision-early-22","level":"early","title":"Precise standup update","scenario":"At standup you said: \"Yesterday I worked on the import thing, today I'll keep going on it.\" Your team can't tell if you're on track or stuck.","task":"Rewrite the update with what you finished, what's next, and any blocker — all specific.","tips":["Name the concrete thing you completed.","Say the specific next step, not 'keep going'.","Flag a blocker with the detail needed to help."],"focus":["precision","structure"]},
    {"id":"precision-early-23","level":"early","title":"Replace 'should work'","scenario":"You handed off a change and wrote: \"This should work now, let me know if not.\" Your reviewer wants to know what you actually verified.","task":"Rewrite it stating exactly what you tested and what you confirmed works.","tips":["Replace 'should work' with what you verified.","Name the cases you checked.","Be honest about what you did not test."],"focus":["precision","clarity"],"placeholder":"This should work now, let me know if not."},
    {"id":"precision-early-24","level":"early","title":"Pick the headline number","scenario":"Your monthly report has ten numbers and your reader has thirty seconds. You're tempted to include all of them so nothing's missed.","task":"Choose one headline number to lead with and write the opening sentence around it.","tips":["Identify the single number your reader most cares about.","Lead with it; relegate the rest.","State why that number is the headline."],"focus":["concision","audience"]},
    {"id":"precision-early-25","level":"early","title":"Specific over 'significant'","scenario":"You wrote in a wrap-up: \"We saw a significant drop in errors after the fix.\" You have the actual numbers: errors fell from 210 a day to 35.","task":"Rewrite the sentence replacing 'significant' with the concrete before-and-after.","tips":["Swap 'significant' for the real figures.","Include the baseline and the timeframe.","Let the numbers do the convincing."],"focus":["precision","impact"],"placeholder":"We saw a significant drop in errors after the fix."}
  ],
  "executive-presence": [
    {"id":"presence-early-01","level":"early","title":"Pick the deploy window","scenario":"Your team is deciding whether to deploy a change Friday afternoon or wait until Monday. Your lead asks what you'd do. You're tempted to say 'either works, whatever you all think.'","task":"Write 2-3 sentences that name your choice and the single reason for it.","tips":["Lead with 'I'd go with...'.","Give one concrete reason, not three.","It's fine to add 'happy to be overruled' at the end."],"focus":["impact","clarity"],"placeholder":"I'd wait until Monday because..."},
    {"id":"presence-early-02","level":"early","title":"Cut the hedging","scenario":"You wrote a Slack message to your manager: 'I just think maybe we should probably consider possibly changing the cache timeout, but I'm not sure.' It buries a good idea under hedges.","task":"Rewrite it as one confident sentence that still leaves room to be wrong.","tips":["Delete 'just', 'maybe', 'probably', 'possibly'.","State the idea, then a brief reason.","One honest qualifier is fine; four is hiding."],"focus":["concision","impact"]},
    {"id":"presence-early-03","level":"early","title":"Recommend, don't list","scenario":"You investigated three libraries for date parsing and wrote them up neutrally with pros and cons. Your manager replied: 'So which one?' You realize you pushed the decision back to them.","task":"Add a 2-3 sentence opening that names your recommendation and the reason it wins.","tips":["Name the pick in sentence one.","Give the deciding factor, not every factor.","Keep the option list below as backup."],"focus":["impact","structure"]},
    {"id":"presence-early-04","level":"early","title":"Fact vs. guess in a bug report","scenario":"A page is loading slowly. You know the API call takes 4 seconds; you suspect it's a missing database index, but you haven't confirmed it.","task":"Write 3 sentences that separate what you measured, what you believe, and how you'd confirm it.","tips":["State the measured fact plainly.","Mark the suspicion as a suspicion, with reasoning.","End with the test that would confirm it."],"focus":["precision","structure"]},
    {"id":"presence-early-05","level":"early","title":"Take a side in standup","scenario":"In a design discussion your team is split on REST vs. a new GraphQL endpoint. Everyone keeps saying 'both have tradeoffs.' You actually have a view.","task":"Write 2-3 sentences stating which you'd build and the one tradeoff that decides it for you.","tips":["Pick a side in the first sentence.","Name the tradeoff that matters most here.","Invite the counter-case without retreating."],"focus":["impact","clarity"]},
    {"id":"presence-early-06","level":"early","title":"Confident status update","scenario":"Your manager asks how your task is going. The truth: it's on track, you're 80% done, one small unknown remains. You're tempted to ramble nervously about everything that could go wrong.","task":"Write a calm 2-3 sentence update that leads with the headline.","tips":["Lead with 'On track' before the details.","Name the one real unknown clearly.","Give a date or next checkpoint."],"focus":["clarity","concision"],"placeholder":"On track — I'm about 80% done. The one open item is..."},
    {"id":"presence-early-07","level":"early","title":"Own the estimate","scenario":"Your lead asks how long a feature will take. You mumble 'um, maybe a few days? Hard to say, could be more.' It sounds like you have no idea.","task":"Write a 2-sentence answer that commits to an estimate and names what could move it.","tips":["Give a real number or range, not 'a while'.","State the one risk that could change it.","Sounding decisive beats sounding cautious here."],"focus":["precision","impact"]},
    {"id":"presence-early-08","level":"early","title":"Signpost a written update","scenario":"Your weekly update to your manager is a wall of sentences about three unrelated things, and it reads like a stream of thought.","task":"Rewrite the opening to signpost the structure: 'Two things this week. First... Second...'","tips":["Tell the reader how many items are coming.","Use 'First / Second' to mark each one.","Keep each item to one tight sentence."],"focus":["structure","clarity"]},
    {"id":"presence-early-09","level":"early","title":"Replace 'I just think'","scenario":"You catch yourself opening every suggestion in code review with 'I just think maybe it'd be a little better if...'. It undercuts good points.","task":"Rewrite one such comment to state the suggestion directly while staying collaborative.","tips":["Drop the 'I just think maybe' opener.","State what you'd change and why.","A question like 'what do you think?' keeps it open without hedging the idea."],"focus":["impact","concision"]},
    {"id":"presence-early-10","level":"early","title":"Recommend in a one-line reply","scenario":"A teammate asks in chat: 'Should we use a feature flag for this or just ship it?' You have an opinion but tend to answer with another question.","task":"Write a one-to-two sentence reply that gives your recommendation and the reason.","tips":["Answer the question before adding nuance.","One reason is enough in chat.","Be brief — this is a quick decision."],"focus":["concision","impact"]},
    {"id":"presence-early-11","level":"early","title":"Flag a risk with a position","scenario":"You think the deadline your team agreed to is unrealistic given the scope. You've been staying quiet because you don't want to seem negative.","task":"Write 2-3 sentences that raise the concern, take a position, and propose a path.","tips":["State the concern as a clear judgment, not a complaint.","Back it with one specific fact about scope or time.","Offer a concrete option, not just the problem."],"focus":["clarity","impact"]},
    {"id":"presence-early-12","level":"early","title":"Stop apologizing for your opinion","scenario":"Your message reads: 'Sorry, this might be a dumb question, but I don't really know much about this — should we maybe roll back?' The apologies drown the actual recommendation.","task":"Rewrite it to ask the question and state your lean with no apologies.","tips":["Cut 'sorry' and 'dumb question'.","Lead with your actual lean: roll back or not.","Confidence and politeness are not opposites."],"focus":["impact","concision"]},
    {"id":"presence-early-13","level":"early","title":"Decisive in a quick decision","scenario":"During pairing, your partner asks 'left nav or top nav for this prototype?' You freeze and list considerations for a minute instead of just choosing.","task":"Write a 1-2 sentence answer that picks one and gives the deciding reason.","tips":["Choose, then justify — in that order.","It's a prototype; decisiveness beats analysis.","One clear reason is plenty."],"focus":["concision","clarity"]},
    {"id":"presence-early-14","level":"early","title":"Own a mistake without spiraling","scenario":"You merged a change that broke the staging build. You want to say something to your team that owns it without ten sentences of anxious self-blame.","task":"Write 2-3 sentences that own it, state the fix, and the next step.","tips":["Own it in one plain sentence — no spiral.","State what you've done or will do to fix it.","Calm ownership reads as more competent than panic."],"focus":["clarity","impact"]},
    {"id":"presence-early-15","level":"early","title":"Recommend in a PR description","scenario":"Your pull request offers two approaches in the description and ends with 'let me know which you prefer.' The reviewer has to do your deciding for you.","task":"Rewrite the closing to state which approach you chose and why, while inviting feedback.","tips":["Say which you implemented and the reason.","Mention the alternative briefly as context.","Invite challenge without removing your stance."],"focus":["impact","structure"]},
    {"id":"presence-early-16","level":"early","title":"Push back on scope, respectfully","scenario":"A teammate asks you to add 'one more small thing' to your task that you think will double the work. You usually just say yes and resent it.","task":"Write 2-3 sentences that take a clear position on the tradeoff and propose how to handle it.","tips":["Name the real cost plainly.","Take a position: now, later, or separate ticket.","Stay collaborative, not combative."],"focus":["clarity","impact"]},
    {"id":"presence-early-17","level":"early","title":"Trim the throat-clearing","scenario":"Your update opens with three sentences of context before the point: 'So as you know, last sprint we had that thing, and then there was the meeting, and anyway...'. The reader is lost before the news arrives.","task":"Rewrite the opening so the actual point is the first sentence.","tips":["Move the headline to sentence one.","Cut the 'as you know' wind-up.","Context can follow the point, briefly."],"focus":["concision","structure"]},
    {"id":"presence-early-18","level":"early","title":"State a clear ask","scenario":"You need your manager to unblock you by approving access to a system, but your message is so soft they might not realize you're actually asking for something.","task":"Write a 2-sentence message that makes the ask explicit and easy to act on.","tips":["Make the ask a clear sentence, not a hint.","Say exactly what you need and by when.","Politeness doesn't require vagueness."],"focus":["clarity","impact"],"placeholder":"Could you approve my access to X? I'm blocked on it for..."},
    {"id":"presence-early-19","level":"early","title":"Answer 'what do you recommend?'","scenario":"In a one-on-one your manager asks which of two tasks you should pick up next. You start listing factors instead of answering.","task":"Write a 2-3 sentence answer that recommends one and gives the reason, then notes what would change your mind.","tips":["Recommend first; reasons second.","Tie the reason to impact or priority.","One 'what would change this' line shows judgment, not doubt."],"focus":["impact","structure"]},
    {"id":"presence-early-20","level":"early","title":"Confident demo intro","scenario":"You're about to demo your work to the team. You tend to open with 'so this is kind of rough and probably has bugs and isn't really done...', which primes everyone to doubt it.","task":"Write a 2-sentence opening that frames the demo with calm confidence and honest scope.","tips":["Say what it does before what it lacks.","Name the scope plainly, without self-deprecation.","Set what feedback you actually want."],"focus":["audience","impact"]},
    {"id":"presence-early-21","level":"early","title":"Separate observation from opinion","scenario":"You're reporting on a flaky test: it failed 3 of 10 runs, and you think it's a race condition, but you're not sure. Your draft blends the two so no one can tell what's confirmed.","task":"Write 2-3 sentences that label the observed behavior and your hypothesis separately.","tips":["State the observation with numbers.","Mark the hypothesis as a hypothesis.","Add how you'd verify it."],"focus":["precision","structure"]},
    {"id":"presence-early-22","level":"early","title":"Disagree with a teammate cleanly","scenario":"In a thread, a teammate proposes an approach you think is wrong. You want to disagree without either caving or sounding harsh.","task":"Write 2-3 sentences that state your differing view and the reason, while acknowledging theirs.","tips":["Acknowledge the valid part of their idea first.","State your position clearly, not as a vague 'hmm'.","Anchor your view to one concrete reason."],"focus":["clarity","audience"]},
    {"id":"presence-early-23","level":"early","title":"Commit to a recommendation in review","scenario":"Your manager asks whether the team should adopt a new linter. You did the research but keep saying 'there are good arguments either way.'","task":"Write 3-4 sentences that recommend yes or no, give the top reason, and note the main downside.","tips":["Decide yes or no — don't sit on the fence.","Lead with the strongest reason.","Name the downside honestly; it makes you credible."],"focus":["impact","structure"]},
    {"id":"presence-early-24","level":"early","title":"Tighten a hedged estimate to a number","scenario":"You wrote: 'It could be done sometime soon-ish, maybe, depending on a few things.' Your manager can't plan around that.","task":"Rewrite it as a committed estimate with the one dependency that could shift it.","tips":["Replace 'soon-ish' with a date or range.","Name the single real dependency.","Confidence here is a date, not a feeling."],"focus":["precision","concision"]},
    {"id":"presence-early-25","level":"early","title":"Close with a clear next step","scenario":"Your message lays out a problem well but trails off with 'so yeah, just wanted to flag it.' Nobody knows what you want to happen next.","task":"Rewrite the ending to state your recommended next step and who you think should do it.","tips":["End with a concrete next step, not a shrug.","Say what you propose, not just the problem.","A clear close turns a flag into a decision."],"focus":["impact","clarity"]}
  ],
  "answering-under-pressure": [
    {"id":"pressure-early-01","level":"early","title":"The standup yes/no","scenario":"In daily standup, your manager cuts in: \"Will the login fix be ready to merge today?\" You think it will, but the code review is still pending. You feel the urge to launch into the whole history of the ticket.","task":"Write a 2-3 sentence answer that gives the direct yes/no/likely first, then the one fact behind it.","tips":["Lead with yes, no, or likely — not the backstory.","Give the single blocker that matters.","Name what you're doing about it."],"focus":["clarity","impact"]},
    {"id":"pressure-early-02","level":"early","title":"I don't have that number","scenario":"In a sprint review, someone asks how many test cases the new feature has. You genuinely don't remember the exact count and don't want to guess wrong in front of the team.","task":"Write a short reply that admits you don't know and attaches a path to the answer.","tips":["Don't bluff a number.","Say how you'll find it and by when.","If you give a rough figure, flag it as unconfirmed."],"focus":["precision","impact"]},
    {"id":"pressure-early-03","level":"early","title":"Why it slipped","scenario":"A teammate asks, a little pointedly, why the task you owned slipped past Friday. It slipped because a dependency from another team came in late, but you don't want to sound like you're blaming anyone.","task":"Write a 2-4 sentence answer that owns your part, states the real cause, and gives the new date.","tips":["Acknowledge the slip plainly before explaining.","State the cause as a fact, not an accusation.","End with the concrete new commitment."],"focus":["structure","precision"]},
    {"id":"pressure-early-04","level":"early","title":"Put on the spot in a meeting","scenario":"In a meeting you didn't expect to speak in, the lead turns to you: \"You worked on this — what do you think we should do?\" Your mind goes blank for a second and you feel everyone looking at you.","task":"Write a composed 2-3 sentence response that gives one clear recommendation, even a tentative one.","tips":["Buy a beat: restate the question in one phrase.","Commit to one direction, not three.","It's fine to say what you'd want to check first."],"focus":["clarity","impact"]},
    {"id":"pressure-early-05","level":"early","title":"The estimate you can't promise","scenario":"Your manager asks how long the refactor will take. You honestly don't know yet — you haven't scoped it. You're tempted to blurt out \"a couple days\" just to have an answer.","task":"Write a reply that avoids a fake number but still gives the manager something to plan around.","tips":["Don't invent a deadline to fill the silence.","Offer a time-boxed way to get a real estimate.","Give a when-you'll-know."],"focus":["precision","impact"]},
    {"id":"pressure-early-06","level":"early","title":"Did you test that edge case?","scenario":"During code review, a senior engineer asks whether you tested the empty-input case. You're pretty sure you did, but not certain, and they're waiting.","task":"Write a short, honest answer that doesn't overclaim and says what you'll do to be sure.","tips":["Don't say 'yes' if you're not certain.","Distinguish what you know from what you assume.","Commit to verifying and reporting back."],"focus":["precision","clarity"]},
    {"id":"pressure-early-07","level":"early","title":"The skeptical follow-up","scenario":"You explain your approach in a design discussion and a teammate replies, \"I'm not sure that scales.\" You feel defensive — but they might have a point.","task":"Write a 2-3 sentence response that acknowledges the valid concern, then addresses it with one specific.","tips":["Concede the legitimate part first.","Answer with a fact, not a justification.","Don't argue the person — address the concern."],"focus":["impact","structure"]},
    {"id":"pressure-early-08","level":"early","title":"Caught not knowing the system","scenario":"In an onboarding meeting, someone asks how the billing service handles retries. You're new and genuinely have no idea yet. Pretending would be easy and risky.","task":"Write a reply that owns the gap as a new person and turns it into a next step.","tips":["It's fine to say you haven't learned that area yet.","Name who or what you'll consult.","Set a quick follow-up so it doesn't dangle."],"focus":["clarity","impact"]},
    {"id":"pressure-early-09","level":"early","title":"Pinned on a root cause","scenario":"A bug hit production and in the post-incident chat your manager asks, \"Do we know what caused it?\" You have a strong hypothesis but no confirmation yet.","task":"Write a 2-3 sentence answer that separates what you know from what you suspect, with a path to certainty.","tips":["Label the confirmed fact vs. the hypothesis.","Don't present a guess as a conclusion.","Say when you'll have the confirmed cause."],"focus":["precision","structure"]},
    {"id":"pressure-early-10","level":"early","title":"The number you half-remember","scenario":"A teammate asks the current error rate on the endpoint you own. You recall it being around 2% but you're not confident, and they may act on whatever you say.","task":"Write a short reply that gives the rough figure but clearly flags it as unconfirmed.","tips":["Mark the estimate as a recollection, not a fact.","Tell them not to act on it until confirmed.","Commit to the exact number and when."],"focus":["precision","concision"]},
    {"id":"pressure-early-11","level":"early","title":"Demo question you didn't expect","scenario":"You're demoing your feature and a stakeholder asks, \"Can it handle our other region too?\" You hadn't considered that and don't actually know.","task":"Write a composed 2-3 sentence response that answers honestly and offers to find out.","tips":["Don't oversell capability you haven't checked.","Say plainly what you'd need to verify.","Offer a concrete follow-up rather than a vague 'maybe'."],"focus":["clarity","impact"]},
    {"id":"pressure-early-12","level":"early","title":"Why did you choose that?","scenario":"In review, your lead asks why you used one library over the obvious alternative. You had a reason but feel the question as a challenge and want to over-justify.","task":"Write a tight 2-3 sentence answer that states the reason directly without sounding defensive.","tips":["Give the decision and the one reason behind it.","Don't pile on five justifications.","If the alternative is reasonable too, say so calmly."],"focus":["concision","clarity"]},
    {"id":"pressure-early-13","level":"early","title":"Are we on track?","scenario":"Mid-sprint, your manager asks the group, \"Is your piece on track for Friday?\" Yours is at risk because of a blocker you've been quietly hoping would resolve itself.","task":"Write an honest 2-3 sentence answer that states the risk plainly and what you need.","tips":["Don't say 'on track' if it isn't.","Name the specific blocker.","Make the ask concrete — what would unblock you."],"focus":["precision","impact"]},
    {"id":"pressure-early-14","level":"early","title":"The question behind the question","scenario":"A teammate asks, \"Is the API doc updated?\" but what they really need is whether they can start integrating today. You realize the literal answer (no) isn't the useful one.","task":"Write a 2-3 sentence reply that answers the literal question, then the real one they need.","tips":["Answer what was asked, then what they need.","Don't leave them with a dead-end 'no'.","Give the path to what they actually want."],"focus":["audience","clarity"]},
    {"id":"pressure-early-15","level":"early","title":"Disagreeing with a senior politely","scenario":"In a discussion a senior engineer states an approach you think won't work. They ask, \"Sound good?\" and the room is waiting for your nod.","task":"Write a 2-3 sentence response that voices the concern directly but respectfully.","tips":["Don't nod along if you disagree.","Frame it as a specific concern, not a verdict.","Offer your reasoning, then ask their take."],"focus":["clarity","audience"]},
    {"id":"pressure-early-16","level":"early","title":"Frozen on a curveball","scenario":"In a planning meeting someone asks, \"What's the riskiest part of this work?\" You hadn't thought about it that way and feel the pressure of silence building.","task":"Write a composed 2-3 sentence answer that names one real risk without rambling.","tips":["Pick one risk, not a survey of all of them.","A short pause to think beats filler words.","Say why it's the riskiest in one phrase."],"focus":["concision","structure"]},
    {"id":"pressure-early-17","level":"early","title":"You missed the meeting context","scenario":"You join a thread late and your manager asks, \"What's your read on the tradeoff we discussed?\" You didn't catch the earlier discussion and don't want to fake it.","task":"Write a short reply that admits you missed the context and gets what you need to answer well.","tips":["Don't improvise an opinion on something you missed.","Ask the one thing you need to catch up.","Commit to a real answer once you have it."],"focus":["clarity","impact"]},
    {"id":"pressure-early-18","level":"early","title":"Defending an estimate that slipped","scenario":"You said two days; it's taken four. Your manager asks, \"What happened with the timeline?\" You feel the urge to list every small obstacle.","task":"Write a 2-3 sentence answer that owns the miss, gives the main cause, and says what you've learned for next time.","tips":["Own the miss before explaining it.","One main cause beats a list of excuses.","End forward-looking, not defensive."],"focus":["structure","impact"]},
    {"id":"pressure-early-19","level":"early","title":"Asked to commit on the spot","scenario":"A teammate asks in chat, \"Can you take this on and finish by Wednesday?\" You're not sure you can without dropping something else, and they want a quick yes.","task":"Write a short, honest reply that doesn't over-promise and surfaces the tradeoff.","tips":["Don't say yes just to be agreeable.","Name what would have to give.","Offer a realistic commitment instead of a hopeful one."],"focus":["precision","clarity"]},
    {"id":"pressure-early-20","level":"early","title":"The 'did you know about this?' question","scenario":"A bug traces back to an assumption you made. A teammate asks, \"Did you know this case could happen?\" You didn't, and it stings to admit.","task":"Write a 2-3 sentence answer that's honest about the gap without spiraling into self-criticism.","tips":["Admit you didn't anticipate it, plainly.","Don't over-apologize or pile on yourself.","Pivot to the fix and the safeguard."],"focus":["clarity","impact"]},
    {"id":"pressure-early-21","level":"early","title":"Status when you're behind","scenario":"In a quick check-in your manager asks for your status and the truth is you've barely started because you were pulled onto something else. You don't want to sound like you've been idle.","task":"Write a 2-3 sentence status that's honest about progress and the reason, without sounding defensive.","tips":["State actual progress first, no padding.","Give the real reason as a fact.","End with your plan to catch up."],"focus":["precision","concision"]},
    {"id":"pressure-early-22","level":"early","title":"Pressed for a recommendation","scenario":"Two approaches are on the table and your lead asks, \"Which would you pick?\" Both have downsides and you're tempted to say \"either works\" to stay safe.","task":"Write a 2-3 sentence answer that picks one and gives the deciding reason.","tips":["Don't hedge with 'either is fine'.","Commit, then give the one reason that tipped you.","Acknowledge the tradeoff in a phrase."],"focus":["impact","structure"]},
    {"id":"pressure-early-23","level":"early","title":"Cornered on a detail you forgot","scenario":"In a review someone asks the exact config value you set last week. You changed it but can't recall the number, and they're waiting for a precise answer.","task":"Write a short reply that doesn't guess the value and gets them an accurate one fast.","tips":["Don't make up a precise number.","Say you'll pull the exact value now.","Give a clear, near-term when."],"focus":["precision","concision"]},
    {"id":"pressure-early-24","level":"early","title":"Staying calm under a sharp tone","scenario":"A frustrated teammate asks, \"Why isn't this done yet?\" in a sharper tone than usual. You feel the heat rise and want to snap back or over-apologize.","task":"Write a composed 2-3 sentence reply that addresses the substance and stays level.","tips":["Don't match the heat — answer the substance.","Give the real status and cause briefly.","Close with the next concrete step."],"focus":["audience","impact"]},
    {"id":"pressure-early-25","level":"early","title":"Honest 'I'm not sure yet'","scenario":"After your demo, a stakeholder asks, \"Are you confident this is ready to ship?\" You have lingering doubts about one path and don't want to give false confidence.","task":"Write a 2-3 sentence answer that's honest about your confidence level and what would raise it.","tips":["Don't claim more confidence than you have.","Name the one thing you're unsure about.","Say what would make you confident, and by when."],"focus":["precision","clarity"]}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-early-01","level":"early","title":"Pitch a second monitor","scenario":"You spend a lot of time flipping between code, docs, and a terminal on a single laptop screen. You believe a second monitor would speed you up, and you want to ask your manager to expense one.","task":"Write a 3-4 sentence ask that frames the before/after and makes the benefit concrete.","tips":["Show 'where I am now' with a specific friction.","Name the after: what gets faster or easier.","Keep the cost small and the payback obvious."],"focus":["impact","structure"],"placeholder":"Right now I lose time flipping between windows on one screen, because…"},
    {"id":"narrative-early-02","level":"early","title":"Make the case to fix flaky tests","scenario":"Your team's test suite fails randomly a couple of times a week, and people just re-run it. You want to spend two days making it reliable, but you suspect your manager will say it's not a priority.","task":"Write a short pitch (3-5 sentences) that quantifies the current pain and pre-empts the 'not a priority' objection.","tips":["Put a number on how often the flakiness costs time.","Name the objection yourself and answer it.","Scope the fix small so the ask feels safe."],"focus":["impact","precision"]},
    {"id":"narrative-early-03","level":"early","title":"Frame a manual task worth automating","scenario":"Every Monday you spend an hour copying numbers into a report by hand. You want a day to script it, but it's invisible work nobody has noticed.","task":"Write a 3-4 sentence ask that contrasts the manual status quo with the automated future.","tips":["Make the recurring cost vivid (an hour every week).","Show the one-time cost versus the ongoing saving.","Name what you'd do with the time back."],"focus":["impact","structure"]},
    {"id":"narrative-early-04","level":"early","title":"Persuade a teammate to pair","scenario":"You're stuck on a tricky bug and a teammate has context you lack. They tend to say they're too busy to pair, so you need to make a short, compelling ask.","task":"Write a 2-3 sentence message that makes pairing feel like a small, worthwhile trade for them.","tips":["Be specific about how much of their time you need.","Frame the benefit to them, not just to you.","Pre-empt the 'I'm busy' reflex with a tight scope."],"focus":["audience","concision"]},
    {"id":"narrative-early-05","level":"early","title":"Ask for a conference ticket","scenario":"There's a relevant conference next month and you'd like the company to cover your ticket. Your manager will wonder what they get back for the cost.","task":"Write a 3-4 sentence request that ties the ask to a concrete benefit for the team.","tips":["Connect what you'll learn to a current team need.","Make the return concrete, not 'general growth'.","Offer to share back what you learn."],"focus":["audience","impact"]},
    {"id":"narrative-early-06","level":"early","title":"Sell a small process change","scenario":"Your team's pull requests sit for days because no one owns reviewing them. You want to propose a light rotation, but people resist new process.","task":"Write a 3-5 sentence pitch that frames the change and disarms the 'more process' objection.","tips":["Name the current pain everyone already feels.","Keep the change as small as possible.","Pre-empt 'this is overhead' by showing the time it saves."],"focus":["structure","audience"]},
    {"id":"narrative-early-07","level":"early","title":"Justify a paid tool subscription","scenario":"A $15/month tool would replace a clunky free workaround you and two teammates use daily. You need your manager to approve the small recurring cost.","task":"Write a 2-4 sentence ask that makes the tiny cost obviously worth it.","tips":["Translate the workaround's friction into time lost.","Compare that time cost to the dollar cost.","Keep it short — the math should carry it."],"focus":["concision","impact"]},
    {"id":"narrative-early-08","level":"early","title":"Before/after a confusing doc","scenario":"New hires keep getting stuck on your team's outdated setup guide and ping people for help. You want time to rewrite it.","task":"Write a 3-4 sentence case that contrasts today's onboarding pain with the after-state.","tips":["Show the repeated cost: every new hire hits the same wall.","Paint the after: self-serve onboarding.","Make the fix sound bounded and doable."],"focus":["impact","structure"]},
    {"id":"narrative-early-09","level":"early","title":"Pre-empt the 'we tried that' objection","scenario":"You want to suggest revisiting an idea the team abandoned a year ago. You know someone will say 'we already tried that and it didn't work.'","task":"Write a 3-5 sentence pitch that raises the 'we tried that' objection and explains what's different now.","tips":["Acknowledge the past attempt honestly.","Name the specific thing that changed.","Don't pretend the old concern was wrong — show it's outdated."],"focus":["precision","audience"]},
    {"id":"narrative-early-10","level":"early","title":"Ask for focus time","scenario":"Back-to-back meetings leave you no uninterrupted block to do deep work, and your output is slipping. You want to ask your manager to protect two mornings a week.","task":"Write a 3-4 sentence ask framing the change and the concrete payoff.","tips":["Make the status quo cost specific (context-switching, slower delivery).","Propose an exact, modest block of time.","Pre-empt 'but you'll miss things' with how you'll stay reachable."],"focus":["clarity","impact"]},
    {"id":"narrative-early-11","level":"early","title":"Make tech debt concrete","scenario":"An old module slows down every feature your team touches, but 'tech debt' sounds abstract to your manager. You want a sprint to clean it up.","task":"Write a 3-5 sentence case that turns the abstract debt into a concrete, felt cost.","tips":["Replace 'tech debt' with a specific recurring slowdown.","Tie it to a number: hours, delays, or bugs.","Show the after-state in terms leadership cares about."],"focus":["precision","impact"]},
    {"id":"narrative-early-12","level":"early","title":"Persuade a peer to adopt your helper","scenario":"You wrote a small script that saves you time, and a teammate on another task could benefit. They're skeptical of 'someone else's tool.'","task":"Write a 2-4 sentence message that makes trying your script low-risk and worthwhile for them.","tips":["Lead with the specific problem of theirs it solves.","Lower the risk: it's quick to try and easy to drop.","Pre-empt 'I'd have to learn it' by showing how simple it is."],"focus":["audience","concision"]},
    {"id":"narrative-early-13","level":"early","title":"Request a deadline extension","scenario":"A task you own will slip by two days because the requirements changed mid-way. You need to ask your manager for the extra time without sounding like you dropped the ball.","task":"Write a 3-4 sentence ask that frames the change in scope and makes the new timeline credible.","tips":["Name what specifically changed, not a vague 'it got harder'.","Show the original plan was sound for the original scope.","Pre-empt worry by stating the concrete new date."],"focus":["clarity","precision"]},
    {"id":"narrative-early-14","level":"early","title":"Frame a small experiment","scenario":"You think changing one default setting could reduce user errors, but you're not certain. You want permission to run a small test.","task":"Write a 3-4 sentence pitch that frames the change and makes the experiment feel safe to approve.","tips":["Show the current problem the default may be causing.","Make the test reversible and bounded.","Pre-empt 'what if it backfires' with how you'll measure and roll back."],"focus":["structure","impact"]},
    {"id":"narrative-early-15","level":"early","title":"Ask to own a piece of work","scenario":"There's an upcoming project you'd love to lead the implementation on, but you're junior and others may be assumed for it. You want to make the case to your manager.","task":"Write a 3-5 sentence pitch that frames why you're the right fit and pre-empts the 'are you ready?' doubt.","tips":["Point to concrete, relevant work you've already done.","Name the readiness objection and answer it.","Show what success looks like, not just your enthusiasm."],"focus":["audience","impact"]},
    {"id":"narrative-early-16","level":"early","title":"Disarm the cost objection","scenario":"You want the team to add an error-monitoring service, but the obvious pushback is the monthly bill. You need to address cost head-on.","task":"Write a 3-4 sentence case that raises the cost objection and reframes it against the cost of not having it.","tips":["State the recommendation, then name the cost concern yourself.","Compare the price to the cost of a missed outage.","Keep the comparison concrete, not hand-wavy."],"focus":["impact","precision"]},
    {"id":"narrative-early-17","level":"early","title":"Pitch documentation time","scenario":"You just finished a tricky integration that only you understand. You want a half-day to document it before context fades, but it feels like 'non-work.'","task":"Write a 2-4 sentence ask that frames the risk of the status quo and the value of writing it down.","tips":["Make the bus-factor risk concrete and personal to the team.","Show the small cost now versus the big cost later.","Keep it tight — the risk should sell itself."],"focus":["concision","impact"]},
    {"id":"narrative-early-18","level":"early","title":"Convince a teammate to change an approach","scenario":"A teammate is building a feature in a way you think will be hard to maintain. You want to suggest a cleaner approach without making them defensive.","task":"Write a 3-5 sentence message that frames the better path and pre-empts 'but mine already works.'","tips":["Acknowledge what their approach gets right.","Show the concrete future cost of the current path.","Frame your idea as a shared win, not a correction."],"focus":["audience","clarity"]},
    {"id":"narrative-early-19","level":"early","title":"Make the stakes of a bug vivid","scenario":"You found a low-severity bug that's been deprioritized, but it quietly frustrates users on every visit. You want your manager to bump its priority.","task":"Write a 3-4 sentence case that turns 'low severity' into a concrete, felt user cost.","tips":["Translate the bug into what a real user experiences.","Show the cumulative cost across many users.","Pre-empt 'it's minor' by reframing frequency as severity."],"focus":["impact","precision"]},
    {"id":"narrative-early-20","level":"early","title":"Ask for a code-review mentor","scenario":"You want a senior teammate to review your PRs more closely for a month to help you grow. You worry they'll see it as extra burden.","task":"Write a 2-4 sentence ask that frames the benefit and lowers the perceived cost to them.","tips":["Be specific about what kind of feedback you're after.","Bound the commitment (a month, your PRs only).","Show how it helps the team, not only you."],"focus":["audience","concision"]},
    {"id":"narrative-early-21","level":"early","title":"Pitch a quick win first","scenario":"You have a big idea to improve the team's deploy process, but it's a lot to swallow at once. You want to propose starting with one small, visible step.","task":"Write a 3-4 sentence pitch that frames a small first step as the bridge to the bigger change.","tips":["Lead with the small, easy-to-approve step.","Show how it proves out the bigger idea.","Pre-empt 'this is a huge change' by shrinking the first ask."],"focus":["structure","impact"]},
    {"id":"narrative-early-22","level":"early","title":"Justify saying no to a side request","scenario":"Another team keeps asking you for small favors that pull you off your committed work. You want to make the case to your manager to push back.","task":"Write a 3-4 sentence message that frames the cost of the interruptions and the trade-off clearly.","tips":["Make the hidden cost of context-switching concrete.","Frame it as a trade-off, not a complaint.","Pre-empt 'but it's only small stuff' with the cumulative total."],"focus":["clarity","impact"]},
    {"id":"narrative-early-23","level":"early","title":"Persuade with a relatable comparison","scenario":"You want a teammate to start writing tests for their work, but 'best practice' arguments bounce off them. You decide to make the case with a concrete, relatable analogy from their own past.","task":"Write a 2-4 sentence message that uses a vivid comparison to make the value of testing land.","tips":["Anchor to a past pain they personally felt.","Keep the analogy simple and specific.","Land on the small habit you're asking for."],"focus":["audience","impact"]},
    {"id":"narrative-early-24","level":"early","title":"Frame a refactor as risk reduction","scenario":"A fragile part of the codebase breaks whenever anyone touches it nearby. You want time to refactor it, but refactors sound like risk to your manager.","task":"Write a 3-5 sentence case that reframes the refactor from 'risky change' to 'reducing ongoing risk.'","tips":["Show the status quo is the real risk, not the refactor.","Quantify how often the fragile code causes problems.","Pre-empt 'refactors are dangerous' with a safe, scoped plan."],"focus":["precision","structure"]},
    {"id":"narrative-early-25","level":"early","title":"Make a one-line ask compelling","scenario":"In your team's standup you have ten seconds to ask for a teammate's help unblocking you later today. You need the ask to be clear and persuasive in a single sentence.","task":"Write one sentence that names what you need, from whom, and why it matters today.","tips":["Lead with the specific ask, not background.","Make the urgency concrete (why today).","Cut every word that isn't load-bearing."],"focus":["concision","clarity"]}
  ],
  "delivering-hard-messages": [
    {"id":"hard-early-01","level":"early","title":"Flag the slip early","scenario":"You committed to finishing a report by Friday, but a dependency came in late and you now know you'll need until Monday. It's Wednesday — your manager doesn't know yet.","task":"Write a 3–4 sentence message that tells your manager the report will slip, gives the new date, and explains why — without burying the news.","tips":["Lead with the slip and the new date — don't make them hunt for it.","Give one honest reason, not a wall of context.","Send it now, while there's still time to adjust."],"placeholder":"Heads up — the report won't be ready Friday. New date is…","focus":["clarity","impact"]},
    {"id":"hard-early-02","level":"early","title":"Own the mistake you made","scenario":"You pushed a config change that broke the staging environment for an hour before you caught it. No one has asked about it yet, but the team noticed the downtime.","task":"Write a short message (3–4 sentences) that owns the mistake plainly, says what you did to fix it, and what you'll do differently.","tips":["Say what happened in the first sentence — no throat-clearing.","Own it without grovelling or over-apologizing.","End with the fix or the prevention, not just the apology."],"placeholder":"That staging outage this morning was mine —","focus":["clarity","precision"]},
    {"id":"hard-early-03","level":"early","title":"Decline the extra task","scenario":"A teammate asks you to take over a recurring report on top of your current work. You're already at capacity and can't add it without dropping something.","task":"Write a 3–4 sentence reply that declines clearly, gives an honest reason, and avoids a false 'maybe'.","tips":["Lead with the no — a clean no helps them plan.","One honest reason beats a pile of excuses.","Offer an alternative only if it's real."],"placeholder":"I can't take the report on right now —","focus":["clarity","audience"]},
    {"id":"hard-early-04","level":"early","title":"Say you're blocked","scenario":"You've been stuck for a day waiting on access to a system another team controls. You kept hoping it would resolve, but it hasn't, and your task can't move without it.","task":"Write a 2–3 sentence message to your manager that names the blocker plainly and asks for the specific help you need.","tips":["Name the blocker in the first line.","Make the ask concrete — who or what would unblock you.","Don't apologize for being blocked; just surface it."],"placeholder":"I'm blocked on the data task — I need access to…","focus":["clarity","concision"]},
    {"id":"hard-early-05","level":"early","title":"Push back on the deadline","scenario":"Your manager casually assumes a task you were assigned will be done by tomorrow. Realistically it's two days of work and tomorrow isn't possible without cutting corners.","task":"Write a 3–4 sentence reply that pushes back on the timeline respectfully and proposes a realistic date or a trade-off.","tips":["State the real estimate plainly, not as a complaint.","Offer a trade-off: scope, date, or help.","Keep it collaborative, not defensive."],"focus":["clarity","structure"]},
    {"id":"hard-early-06","level":"early","title":"Admit you're stuck","scenario":"You've spent three hours on a bug and made no progress. You're worried that asking for help looks like you can't handle it, but you're genuinely stuck.","task":"Write a 2–3 sentence message asking a senior teammate for help that's specific about what you've tried.","tips":["Lead with the ask — don't pad it with reassurance.","Say what you've already tried so they don't repeat it.","Being specific signals competence, not weakness."],"placeholder":"I'm stuck on the login bug — I've tried…","focus":["concision","precision"]},
    {"id":"hard-early-07","level":"early","title":"Correct your own estimate","scenario":"Last week you told your manager a feature would take 'a couple of days.' You've since realized it's closer to a week. The sooner you reset expectations, the better.","task":"Write a 3–4 sentence update that corrects your earlier estimate clearly and gives the revised timeline.","tips":["Name the revision up front — don't soften it into vagueness.","Briefly say what you learned that changed the estimate.","Give a concrete new number, not 'a bit longer'."],"focus":["clarity","precision"]},
    {"id":"hard-early-08","level":"early","title":"Give a peer light feedback","scenario":"A peer's pull requests keep landing with no description, so you spend extra time figuring out what changed. You want to raise it kindly but directly.","task":"Write a 3–4 sentence message using behavior → impact → ask. Keep it about the work, not their character.","tips":["Name the exact behavior — no labels like 'careless'.","State the concrete impact on you or the team.","End with a clear, doable ask."],"focus":["precision","audience"]},
    {"id":"hard-early-09","level":"early","title":"Decline the after-hours ask","scenario":"A teammate messages at 6pm asking you to jump on a 'quick' task tonight. It isn't urgent and you have plans. You want to set a boundary without seeming uncommitted.","task":"Write a 2–3 sentence reply that declines tonight, offers when you can do it, and keeps the tone warm.","tips":["Decline clearly — don't leave a vague maybe.","Offer a concrete alternative time.","No long justification; one line of reason is enough."],"focus":["clarity","audience"]},
    {"id":"hard-early-10","level":"early","title":"Flag the scope creep","scenario":"A project you're on has quietly grown — three new asks were added without removing anything, and the original deadline hasn't moved. You need to raise it before it becomes a crunch.","task":"Write a 3–4 sentence message that names the scope growth plainly and asks for a priority call or a date change.","tips":["State the mismatch clearly: scope grew, date didn't.","Make the ask a decision they can make.","Frame it as protecting quality, not complaining."],"focus":["structure","impact"]},
    {"id":"hard-early-11","level":"early","title":"Own the missed message","scenario":"You missed an email asking you to review something, and the deadline passed two days ago. The sender just followed up, clearly frustrated.","task":"Write a 2–3 sentence reply that owns the miss directly, doesn't over-explain, and proposes a fast next step.","tips":["Acknowledge the miss in the first sentence.","Skip the excuses — they read as defensive.","Pivot quickly to when you'll deliver."],"placeholder":"You're right — I missed this, that's on me.","focus":["concision","clarity"]},
    {"id":"hard-early-12","level":"early","title":"Say no to the meeting","scenario":"You've been invited to a recurring meeting that doesn't really need you — you'd just be listening. You want to opt out without seeming disengaged.","task":"Write a 2–3 sentence reply that declines the standing invite and offers to stay in the loop another way.","tips":["Be direct that you'll step out of the meeting.","Offer a lighter-touch alternative (notes, async updates).","Keep it positive — you're optimizing, not checking out."],"focus":["concision","audience"]},
    {"id":"hard-early-13","level":"early","title":"Report the bug you shipped","scenario":"A small feature you built has a bug that's affecting a few users. You found it yourself before anyone reported it. You need to tell your manager and the affected team.","task":"Write a 3–4 sentence message that states the bug, its impact, and your plan to fix it — leading with the problem, not the backstory.","tips":["Headline the bug and who's affected first.","Be specific about scope so no one over- or under-reacts.","End with the fix and a timeline."],"focus":["structure","precision"]},
    {"id":"hard-early-14","level":"early","title":"Push back on unclear requirements","scenario":"You were handed a ticket that's too vague to start — you'd be guessing at what 'done' means. You don't want to look like you're stalling, but you can't build it blind.","task":"Write a 2–3 sentence message that flags the gap and asks the specific question that would unblock you.","tips":["State plainly that the requirements are unclear.","Ask one precise question, not five vague ones.","Frame it as wanting to build the right thing."],"focus":["clarity","precision"]},
    {"id":"hard-early-15","level":"early","title":"Decline scope you can't own","scenario":"A teammate asks you to lead a piece of work that's well outside your experience and would set you up to fail. You want to be honest without seeming unwilling.","task":"Write a 3–4 sentence reply that declines this specific ask, gives the honest reason, and suggests a better path.","tips":["Say no to the ask, yes to helping where you can.","Be honest about the skills gap, briefly.","Suggest who or what would fit better."],"focus":["clarity","audience"]},
    {"id":"hard-early-16","level":"early","title":"Tell them the numbers were wrong","scenario":"You sent a dashboard last week and just realized a calculation was off — the figures people have been quoting are wrong. You need to correct the record fast.","task":"Write a 3–4 sentence message that states the error plainly, gives the corrected figures, and flags who needs to know.","tips":["Lead with 'the numbers were wrong' — don't soften it.","Give the correct figures immediately.","Own it cleanly; speed matters more than apology."],"placeholder":"Correction on last week's dashboard — one figure was off.","focus":["precision","clarity"]},
    {"id":"hard-early-17","level":"early","title":"Set a focus boundary","scenario":"A teammate keeps pinging you with non-urgent questions throughout the day, breaking your focus on a deadline-critical task. You want to set a boundary without being cold.","task":"Write a 2–3 sentence message that asks them to batch non-urgent questions, kindly and clearly.","tips":["Make the ask specific (e.g. batch, or use a thread).","Explain the why in one line — the deadline.","Keep it warm so it doesn't read as a brush-off."],"focus":["audience","concision"]},
    {"id":"hard-early-18","level":"early","title":"Admit you don't understand","scenario":"In a planning thread, everyone's discussing an approach using terms and assumptions you don't follow. Nodding along would mean building the wrong thing.","task":"Write a 2–3 sentence message that admits you're not following and asks for the clarification you need.","tips":["Say plainly that you're not following — it's not a failing.","Pinpoint exactly what's unclear.","Frame it as wanting to get it right."],"placeholder":"Want to make sure I'm tracking this correctly —","focus":["clarity","concision"]},
    {"id":"hard-early-19","level":"early","title":"Decline the unrealistic ask","scenario":"Your manager asks you to add a 'small' feature to this week's release. You know it isn't small — it would risk the whole release if rushed.","task":"Write a 3–4 sentence reply that pushes back on fitting it into this release and proposes a realistic option.","tips":["Be clear it doesn't fit this release, and why.","Quantify the real cost briefly.","Offer a path: next release, or cut something."],"focus":["clarity","impact"]},
    {"id":"hard-early-20","level":"early","title":"Own the dropped handoff","scenario":"You forgot to hand off a task before going on leave, and a teammate got stuck covering it with no context. They're back-channeling their frustration.","task":"Write a 3–4 sentence message that owns the dropped handoff, acknowledges the impact on them, and offers to make it right.","tips":["Acknowledge the miss and its impact on them first.","Don't hide behind 'it was a busy week'.","Offer a concrete way to help now."],"focus":["audience","clarity"]},
    {"id":"hard-early-21","level":"early","title":"Flag the risk no one's naming","scenario":"You're fairly sure the team's current plan will miss its date, but everyone's acting optimistic and no one has said it. You're junior and hesitant to be the one to raise it.","task":"Write a 3–4 sentence message that names the risk plainly, with the evidence, and asks the team to address it.","tips":["State the risk directly — vagueness helps no one.","Back it with one concrete data point.","End with a constructive ask, not just alarm."],"focus":["structure","impact"]},
    {"id":"hard-early-22","level":"early","title":"Ask for the review you need","scenario":"Your work has been sitting in review for three days and the reviewer keeps going quiet. The delay is now putting your own deadline at risk, and you've held back from nudging.","task":"Write a 2–3 sentence message that asks for the review directly and explains why it's time-sensitive now.","tips":["Make the ask plainly — a polite nudge is fair.","Tie it to a concrete deadline impact.","Keep it short; no apology for following up."],"focus":["concision","clarity"]},
    {"id":"hard-early-23","level":"early","title":"Give your manager upward feedback","scenario":"Your manager assigns tasks in scattered Slack messages, and things fall through the cracks. They asked for honest feedback in your last 1:1. You want to raise it constructively.","task":"Write a 3–4 sentence message using behavior → impact → ask, pitched respectfully to your manager.","tips":["Name the specific behavior, not a complaint about style.","State the concrete impact (things getting missed).","Make a doable ask, like a single tracked list."],"focus":["precision","audience"]},
    {"id":"hard-early-24","level":"early","title":"Decline without a real reason","scenario":"A colleague invites you to join a side project you genuinely don't want to do. There's no scheduling conflict to point to — you just don't want it. You need to decline honestly but kindly.","task":"Write a 2–3 sentence reply that declines clearly without inventing a fake excuse, while staying warm.","tips":["A clean no doesn't require a dramatic reason.","Don't invent a conflict — it traps you later.","Keep the relationship warm with genuine thanks."],"focus":["clarity","audience"]},
    {"id":"hard-early-25","level":"early","title":"Tell them it can't all ship","scenario":"You're carrying three deadlines that all land the same day, and you now know you can't hit all of them well. Your manager assumes everything is on track.","task":"Write a 3–4 sentence message that surfaces the conflict early and asks your manager to help prioritize.","tips":["Surface the conflict before the deadline, not after.","Lay out the three items and the real constraint.","Hand them a prioritization decision, not a panic."],"placeholder":"I want to flag a timing conflict before it bites us —","focus":["structure","clarity"]}
  ],
  "putting-it-together": [
    {"id":"capstone-early-01","level":"early","title":"Weekly status email","scenario":"It's Friday and you owe your manager your weekly status update. This week you shipped the export feature, got blocked two days on a flaky test environment, and you need a code review before Monday to stay on track.","task":"Write a status email (5-7 sentences) that leads with where the work stands, groups progress and blockers, and ends with your one ask.","tips":["First line: are you on track or not?","Separate done, in-progress, and blocked.","Make the review ask specific with a deadline.","Cut weekend pleasantries and filler."],"focus":["structure","concision","impact"],"placeholder":"Hi Dana — heading into next week, the export feature is..."},
    {"id":"capstone-early-02","level":"early","title":"Reply to a tough manager email","scenario":"Your manager emailed asking, somewhat pointedly, why the dashboard ticket slipped a week. The real reason is that requirements changed twice mid-sprint and you weren't told until late. You want to answer honestly without sounding defensive.","task":"Draft a reply (4-6 sentences) that leads with the answer, gives the precise cause, and proposes how to prevent it next time.","tips":["Lead with the direct answer, not the backstory.","State facts, not blame.","Replace 'things kept changing' with the specific changes.","End with a concrete prevention step."],"focus":["clarity","precision","audience"]},
    {"id":"capstone-early-03","level":"early","title":"Pull request description","scenario":"You're opening a PR that refactors the payment retry logic and fixes a bug where failed charges were retried indefinitely. Reviewers are busy and skim. You want the description to make review fast.","task":"Write a PR description that opens with what changed and why, then lists the key changes and how you tested.","tips":["First line: what this PR does, in plain terms.","Separate 'what' from 'how to verify'.","Name the bug behavior precisely.","Drop anything a reviewer wouldn't act on."],"focus":["structure","precision","concision"]},
    {"id":"capstone-early-04","level":"early","title":"Customer support reply","scenario":"A customer wrote in frustrated that their report exported with missing rows. You found the cause — a date filter defaulting to the wrong range — and it's now fixed for them. You want to reply in a way that rebuilds trust.","task":"Write a reply (4-6 sentences) that leads with the resolution, explains plainly what happened, and tells them what to do next.","tips":["Lead with 'fixed', not an apology paragraph.","Explain the cause in their words, not yours.","Be warm but direct — don't grovel.","End with one clear next step."],"focus":["clarity","audience","impact"]},
    {"id":"capstone-early-05","level":"early","title":"Asking for a deadline extension","scenario":"A feature you committed to for Thursday won't be ready — a dependency you relied on shipped a breaking change. You can deliver a solid version by Tuesday. You're messaging the project lead.","task":"Write the request (4-6 sentences) that states the new date up front, gives the real reason, and shows you have a plan.","tips":["Open with the new realistic date.","Give the precise cause in one line.","Show what you're doing to recover.","Don't bury the ask under apologies."],"focus":["clarity","structure","impact"]},
    {"id":"capstone-early-06","level":"early","title":"Project recap to stakeholders","scenario":"You wrapped a three-week project migrating the team's logging to a new tool. People who weren't close to it want to know what changed and whether anything affects them.","task":"Write a recap (5-7 sentences) that leads with the outcome, summarizes what changed, and flags the one thing readers need to do.","tips":["First sentence: the result, not the journey.","Group outcome, what changed, and action needed.","Translate technical detail for a mixed audience.","Cut the day-by-day narrative."],"focus":["structure","audience","concision"]},
    {"id":"capstone-early-07","level":"early","title":"Flagging a risk early","scenario":"Mid-sprint you realize the API rate limits will likely break the import feature at the volumes the client expects. Nothing has failed yet, but it will. You're writing to your tech lead before it becomes a fire.","task":"Write the heads-up (4-6 sentences) that names the risk first, quantifies it, and proposes options.","tips":["Lead with the risk and its impact.","Use specific numbers, not 'might be a problem'.","Offer 1-2 options, not just the problem.","Keep it short enough to read on a phone."],"focus":["precision","impact","concision"]},
    {"id":"capstone-early-08","level":"early","title":"Standup-blocker message","scenario":"You can't make today's standup, so you're posting your update in the team channel. You're blocked waiting on design specs for the settings screen, and you have a question about the password rules that someone needs to answer.","task":"Write a channel post that makes your status, blocker, and question scannable at a glance.","tips":["Put the blocker where it can't be missed.","Separate status from the ask.","Tag or name who can unblock you.","Be specific about what you need and by when."],"focus":["structure","clarity","concision"]},
    {"id":"capstone-early-09","level":"early","title":"Bug report that gets actioned","scenario":"You found a bug where users get logged out after exactly 15 minutes regardless of activity. You're filing the ticket so an on-call engineer can reproduce and fix it without pinging you for details.","task":"Write the report with a clear summary line, then precise steps to reproduce, expected vs. actual behavior.","tips":["Summary line states the symptom in one sentence.","Steps should be exact and repeatable.","Separate expected from actual explicitly.","Cut speculation about the cause unless you're sure."],"focus":["precision","structure","clarity"]},
    {"id":"capstone-early-10","level":"early","title":"Saying no to extra scope","scenario":"A peer from another team asks you to add a 'small' extra field to the report you're building, mid-sprint. It's not small, and it's not in your committed work. You want to decline without being a jerk or overstepping.","task":"Write a reply (4-6 sentences) that gives a clear answer, explains the trade-off, and offers a path forward.","tips":["Lead with a clear position, not a maybe.","Name the trade-off concretely (what slips).","Stay collaborative — offer a next step.","Don't pad the no with five qualifiers."],"focus":["clarity","audience","impact"]},
    {"id":"capstone-early-11","level":"early","title":"Demo summary for those who missed it","scenario":"You demoed the new onboarding flow at sprint review. Several teammates and your PM couldn't attend and asked for a recap. You want them to know what works, what's left, and what feedback you got.","task":"Write a recap (5-7 sentences) that leads with the headline, groups the three areas, and notes any decision needed.","tips":["First line: the one-sentence headline.","Group: what's done, what's open, feedback.","Surface any decision they owe you.","Keep it skimmable — short groups, not a wall."],"focus":["structure","concision","impact"]},
    {"id":"capstone-early-12","level":"early","title":"Escalating a stuck dependency","scenario":"You've been blocked for three days waiting on another team to merge a shared library change. Polite reminders haven't moved it. You need to escalate to your manager without throwing the other team under the bus.","task":"Write the escalation (4-6 sentences) that states the impact first, gives the timeline of what you've tried, and asks for specific help.","tips":["Lead with what's blocked and the cost.","Show you tried the direct route first.","Be factual about the other team, not accusatory.","Ask for a specific intervention."],"focus":["impact","precision","audience"]},
    {"id":"capstone-early-13","level":"early","title":"Clarifying ambiguous requirements","scenario":"A ticket says 'make the search faster' with no target or definition. Before you start, you need to pin down what 'faster' means so you don't build the wrong thing. You're replying to the PM who wrote it.","task":"Write a reply (4-6 sentences) that asks the precise questions you need answered, framed so they're easy to respond to.","tips":["Lead with why you're asking, briefly.","Make questions specific and answerable.","Offer a default so they can just confirm.","Don't ask ten questions — ask the load-bearing ones."],"focus":["precision","clarity","audience"]},
    {"id":"capstone-early-14","level":"early","title":"Owning a mistake you made","scenario":"You pushed a config change that briefly took down the staging environment for an hour. It's restored now. Your team noticed. You want to own it cleanly in the channel rather than let it fester.","task":"Write a short message that states what happened, takes responsibility, and says what you've changed to prevent it.","tips":["Lead with the facts and ownership.","No defensiveness, no over-apology.","Name the concrete safeguard you added.","Keep it brief — accountability, not a confession."],"focus":["clarity","impact","concision"]},
    {"id":"capstone-early-15","level":"early","title":"Handoff notes before time off","scenario":"You're off for a week and a teammate is covering your tickets. They don't have your context on the two in-flight items, one of which has a flaky deploy step.","task":"Write handoff notes that lead with what's urgent, then give just enough context per item to act without you.","tips":["Order by what's most likely to come up.","Give the gotcha, not your whole mental model.","Name who to ask if they're stuck.","Be precise about the flaky step's workaround."],"focus":["structure","precision","audience"]},
    {"id":"capstone-early-16","level":"early","title":"Proposing a small improvement","scenario":"You noticed the team re-types the same three commands for every deploy and you've scripted it. You want to pitch adopting your script to the team lead without overselling a 20-line file.","task":"Write the pitch (4-6 sentences) that leads with the benefit, shows the cost it removes, and makes the ask easy.","tips":["Open with the payoff, not the backstory.","Quantify the friction it removes.","Right-size the tone — it's a 20-line script.","End with a low-effort next step to try it."],"focus":["impact","concision","audience"]},
    {"id":"capstone-early-17","level":"early","title":"Replying to negative review feedback","scenario":"A senior engineer left blunt review comments calling your approach 'overcomplicated'. Some points are fair, one you disagree with for a real reason. You want to respond professionally and move the PR forward.","task":"Write a reply (4-6 sentences) that acknowledges the fair points, defends the one you disagree with using evidence, and proposes next steps.","tips":["Lead with what you'll change — show you heard them.","Defend with a reason, not ego.","Keep tone even and specific.","End by moving the review forward."],"focus":["audience","precision","clarity"]},
    {"id":"capstone-early-18","level":"early","title":"Release notes for users","scenario":"Your team is shipping an update with one big new feature (bulk editing), two bug fixes, and a small UI change. You're writing the user-facing release notes for the changelog.","task":"Write release notes that lead with the headline feature and group the rest so users scan in seconds.","tips":["Headline the thing users care about most.","Group by what's new vs. what's fixed.","Write benefits, not internal jargon.","Trim each item to one clear line."],"focus":["audience","structure","concision"]},
    {"id":"capstone-early-19","level":"early","title":"Requesting a focused review meeting","scenario":"You're stuck on an architecture decision for the caching layer and async messages aren't resolving it. You want 30 minutes with two senior engineers, but they're busy, so the request has to justify itself fast.","task":"Write the meeting request (4-6 sentences) that states the decision needed, why it needs live discussion, and what you'll bring.","tips":["Lead with the exact decision on the table.","Justify why it can't be async.","Show you've done the prep.","Make it easy to say yes — propose a tight scope."],"focus":["clarity","impact","concision"]},
    {"id":"capstone-early-20","level":"early","title":"Translating a technical issue for a PM","scenario":"The PM asks why the new feature feels slow. The cause is N+1 database queries, but the PM isn't technical. You need to explain the problem, impact, and fix timeline in terms they can act on.","task":"Write an explanation (4-6 sentences) that leads with impact, explains the cause in plain language, and gives a timeline.","tips":["Lead with what the user experiences.","Use an analogy, not the jargon term.","Connect it to the fix and the timeline.","Don't make them learn databases to get the point."],"focus":["audience","clarity","precision"]},
    {"id":"capstone-early-21","level":"early","title":"Declining a meeting politely","scenario":"You're invited to a recurring planning meeting that overlaps your only focused coding block, and your input isn't really needed live — async notes would do. You want to opt out without seeming disengaged.","task":"Write the reply (3-5 sentences) that declines clearly, explains the trade-off, and offers how you'll stay in the loop.","tips":["Give a clear answer, not a hedge.","Name the real reason briefly.","Offer an async alternative.","Keep it warm and short."],"focus":["clarity","audience","concision"]},
    {"id":"capstone-early-22","level":"early","title":"Summarizing research for a decision","scenario":"Your lead asked you to evaluate two libraries for date handling. You spent a day testing both. They want a recommendation, not a research paper — but they'll trust it more if the reasoning is clear.","task":"Write a summary (5-7 sentences) that states your recommendation first, then the two or three reasons that decided it.","tips":["Open with your pick — take a position.","Give the decisive reasons, not every detail.","Note the main trade-off honestly.","Cut the exploration you did that didn't matter."],"focus":["impact","structure","concision"]},
    {"id":"capstone-early-23","level":"early","title":"Reporting a partial result","scenario":"Your manager asked for the load-test results by end of day. You have results for two of three scenarios; the third is still running and won't finish until morning. You want to give them what's useful now.","task":"Write the update (4-6 sentences) that leads with the headline finding, reports what's done precisely, and sets expectations on the rest.","tips":["Lead with the finding that matters most so far.","Be precise about what's done vs. pending.","Give a real ETA for the remainder.","Don't dress up partial as complete."],"focus":["precision","clarity","impact"]},
    {"id":"capstone-early-24","level":"early","title":"Onboarding note to a new teammate","scenario":"A new hire joins your team next week and you're the buddy. You want to send a welcome note that orients them: the few things to set up first, who to ask for what, and one piece of advice that actually helps.","task":"Write the note (5-7 sentences) that leads with the warm welcome, groups the practical setup, and keeps it scannable.","tips":["Open warm, then get practical fast.","Group setup steps and who-to-ask.","Pick the few things that matter day one.","Don't dump the whole wiki on them."],"focus":["audience","structure","concision"]},
    {"id":"capstone-early-25","level":"early","title":"The all-in-one status reply","scenario":"Your manager replies to your status with three things at once: a question about the export bug, approval to proceed on the redesign, and a nudge about an overdue doc. You want to answer all three cleanly in one reply.","task":"Write a reply that addresses all three points in a clear structure so nothing gets lost.","tips":["Answer the question first and directly.","Signpost each of the three so they're distinct.","Confirm the approval and the doc with specifics.","Keep each part tight — one reply, three clean answers."],"focus":["structure","clarity","concision"]}
  ],
};
